output:
Two issues:
1. On Nano Matter, passing SDA/SCL as integer pin numbers to Wire.begin() may not resolve correctly depending on the core version. Use Wire.begin() with no arguments to use default I2C0 pins.
2. The Nano Matter has two I2C buses (I2C0 and I2C1). Verify your device is wired to the correct I2C bus pins per the pinout diagram.

Fixed:
```cpp
#include <Wire.h>
void setup() {
  Serial.begin(9600);
  while (!Serial);
  Wire.begin(); // use default I2C0 pins
  Serial.println("Scanning...");
}
void loop() {
  for (byte addr = 1; addr < 127; addr++) {
    Wire.beginTransmission(addr);
    byte err = Wire.endTransmission();
    if (err == 0) {
      Serial.print("Found: 0x");
      Serial.println(addr, HEX);
    }
  }
  delay(5000);
}
```

