const int SENSOR_PIN = A0;
const float VCC = 5.0;
const float RL = 10000.0; // 10kΩ load resistor
const int CALIBRATION_SAMPLES = 200;

float R0 = 0;

float readRS() {
  int raw = analogRead(SENSOR_PIN);
  float voltage = raw * (VCC / 1023.0);
  return RL * (VCC - voltage) / voltage;
}

void calibrate() {
  Serial.println("Calibrating sensor in clean air...");
  Serial.println("Ensure no gas sources are nearby.");
  float sum = 0;
  for (int i = 0; i < CALIBRATION_SAMPLES; i++) {
    sum += readRS();
    delay(50);
    if (i % 20 == 0) Serial.print(".");
  }
  R0 = sum / CALIBRATION_SAMPLES;
  Serial.println();
  Serial.print("Calibrated R0: "); Serial.println(R0);
  Serial.println("Store this value as your baseline R0 constant.");
}

void setup() {
  Serial.begin(115200);
  delay(120000); // 2 min preheat before calibration
  calibrate();
}

void loop() {
  float RS = readRS();
  float ratio = RS / R0;
  Serial.print("RS/R0: "); Serial.println(ratio, 4);
  delay(1000);
}

