output:
The issue is reading without synchronizing to frame boundaries. UART data is a continuous stream. If you call readBytes(32) and you're not at the start of a frame, you'll read bytes 2–33 of one frame, which obviously won't start with 0x42 0x4D.

Fix: Scan for the start bytes before reading the rest of the frame:

  void loop() {
    if (pms.available() < 2) return;

    // Scan for start of frame
    if (pms.peek() != 0x42) {
      pms.read(); // discard and resync
      return;
    }
    pms.read(); // consume 0x42
    if (pms.read() != 0x4D) return; // not a valid start

    // Now read the remaining 30 bytes
    if (pms.available() < 30) return;
    uint8_t buf[30];
    pms.readBytes(buf, 30);

    uint16_t pm25 = (buf[6] << 8) | buf[7]; // atmospheric PM2.5
    Serial.println(pm25);
  }

