// EPA 2024 PM2.5 AQI breakpoints
// Source: EPA AQI Technical Assistance Document, 2024 revision
// New annual standard: 9 ug/m3; 24-hour: 35 ug/m3

struct AQIBreakpoint {
  float cLow, cHigh;
  int iLow, iHigh;
  const char* category;
};

AQIBreakpoint PM25_BREAKPOINTS[] = {
  {0.0,   9.0,    0,  50,  "Good"},
  {9.1,   35.4,   51, 100, "Moderate"},
  {35.5,  55.4,  101, 150, "Unhealthy for Sensitive Groups"},
  {55.5, 125.4,  151, 200, "Unhealthy"},
  {125.5, 225.4, 201, 300, "Very Unhealthy"},
  {225.5, 325.4, 301, 500, "Hazardous"}
};

int calculateAQI(float pm25) {
  for (auto &bp : PM25_BREAKPOINTS) {
    if (pm25 >= bp.cLow && pm25 <= bp.cHigh) {
      return (int)((bp.iHigh - bp.iLow) / (bp.cHigh - bp.cLow)
             * (pm25 - bp.cLow) + bp.iLow);
    }
  }
  return -1;
}

const char* getCategory(int aqi) {
  for (auto &bp : PM25_BREAKPOINTS) {
    if (aqi >= bp.iLow && aqi <= bp.iHigh) return bp.category;
  }
  return "Beyond AQI";
}

void setup() {
  Serial.begin(115200);
  float testPM = 22.5;
  int aqi = calculateAQI(testPM);
  Serial.print("PM2.5: "); Serial.print(testPM); Serial.println(" ug/m3");
  Serial.print("AQI: "); Serial.println(aqi);
  Serial.print("Category: "); Serial.println(getCategory(aqi));
}

void loop() {}

