#define MQ7_HEATER_PIN 9   // PWM-capable pin
#define MQ7_ANALOG_PIN A0

// MQ-7 heater cycle: 5V for 60s, then 1.4V for 90s
// 1.4V ≈ 255 * (1.4/5.0) = ~71 PWM duty
#define HIGH_HEAT_PWM 255
#define LOW_HEAT_PWM  71
#define HIGH_HEAT_MS  60000UL
#define LOW_HEAT_MS   90000UL

unsigned long cycleStart = 0;
bool highPhase = true;

void setup() {
  Serial.begin(9600);
  pinMode(MQ7_HEATER_PIN, OUTPUT);
  analogWrite(MQ7_HEATER_PIN, HIGH_HEAT_PWM);
  cycleStart = millis();
  Serial.println("MQ-7 warming up (48h recommended for first use)");
}

void loop() {
  unsigned long elapsed = millis() - cycleStart;

  if (highPhase && elapsed >= HIGH_HEAT_MS) {
    analogWrite(MQ7_HEATER_PIN, LOW_HEAT_PWM);
    highPhase = false;
    cycleStart = millis();
  } else if (!highPhase && elapsed >= LOW_HEAT_MS) {
    analogWrite(MQ7_HEATER_PIN, HIGH_HEAT_PWM);
    highPhase = true;
    cycleStart = millis();
  }

  // Read CO only during the last 10 seconds of the low-heat phase
  if (!highPhase && elapsed >= (LOW_HEAT_MS - 10000UL)) {
    int raw = analogRead(MQ7_ANALOG_PIN);
    float voltage = raw * (5.0 / 1023.0);
    Serial.print("CO raw ADC: "); Serial.print(raw);
    Serial.print("  Voltage: "); Serial.println(voltage);
  }

  delay(100);
}

