import serial
import struct
import time

def read_pms5003(ser):
    """Read one 32-byte frame from PMS5003."""
    while True:
        byte = ser.read(1)
        if byte == b'\x42':
            next_byte = ser.read(1)
            if next_byte == b'\x4d':
                frame = ser.read(30)  # Remaining 30 bytes
                if len(frame) == 30:
                    return struct.unpack('>HHHHHHHHHHHHHH', frame[:28])
    return None

def pm25_to_aqi(pm25):
    """Simplified US EPA PM2.5 AQI calculation."""
    breakpoints = [
        (0, 12.0, 0, 50),
        (12.1, 35.4, 51, 100),
        (35.5, 55.4, 101, 150),
        (55.5, 150.4, 151, 200),
        (150.5, 250.4, 201, 300),
    ]
    for c_lo, c_hi, i_lo, i_hi in breakpoints:
        if c_lo <= pm25 <= c_hi:
            return int((i_hi - i_lo) / (c_hi - c_lo) * (pm25 - c_lo) + i_lo)
    return 301  # Hazardous

ser = serial.Serial('/dev/ttyAMA0', baudrate=9600, timeout=2)

while True:
    data = read_pms5003(ser)
    if data:
        # Standard concentration values (indices 2,3,4 = PM1.0, PM2.5, PM10)
        pm1  = data[2]
        pm25 = data[3]
        pm10 = data[4]
        aqi  = pm25_to_aqi(pm25)
        print(f'PM1.0: {pm1} µg/m³  PM2.5: {pm25} µg/m³  PM10: {pm10} µg/m³  AQI: {aqi}')
    time.sleep(1)

