typedef struct {
  float kp, ki, kd;
  float prev_error;
  float integral;
  float integral_limit;
} PID;

void PID_Init(PID *pid, float kp, float ki, float kd, float int_limit) {
  pid->kp = kp;
  pid->ki = ki;
  pid->kd = kd;
  pid->prev_error = 0.0f;
  pid->integral = 0.0f;
  pid->integral_limit = int_limit;
}

float PID_Compute(PID *pid, float setpoint, float measured, float dt) {
  float error = setpoint - measured;

  pid->integral += error * dt;
  // Anti-windup
  if (pid->integral > pid->integral_limit) pid->integral = pid->integral_limit;
  if (pid->integral < -pid->integral_limit) pid->integral = -pid->integral_limit;

  float derivative = (error - pid->prev_error) / dt;
  pid->prev_error = error;

  return (pid->kp * error) + (pid->ki * pid->integral) + (pid->kd * derivative);
}

// Usage example
int main() {
  PID roll_pid;
  PID_Init(&roll_pid, 1.2f, 0.05f, 0.8f, 400.0f);

  float dt = 0.004f; // 250Hz loop
  float setpoint = 0.0f; // Level flight
  float measured_roll = 5.5f; // From IMU

  float output = PID_Compute(&roll_pid, setpoint, measured_roll, dt);
  // Apply output to motor mix
  return 0;
}
```
Anti-windup clamping prevents integral term from growing unbounded during saturation. dt should match your actual loop frequency — 250Hz (4ms) is standard for flight controllers.

