TIM_HandleTypeDef htim3;

void TIM3_PWM_Init() {
  TIM_OC_InitTypeDef sConfigOC = {0};

  htim3.Instance = TIM3;
  htim3.Init.Prescaler = 83;        // 84MHz / (83+1) = 1MHz
  htim3.Init.CounterMode = TIM_COUNTERMODE_UP;
  htim3.Init.Period = 19999;        // 1MHz / 20000 = 50Hz (20ms period)
  htim3.Init.ClockDivision = TIM_CLOCKDIVISION_DIV1;
  HAL_TIM_PWM_Init(&htim3);

  sConfigOC.OCMode = TIM_OCMODE_PWM1;
  sConfigOC.Pulse = 1000;           // 1ms = min throttle
  sConfigOC.OCPolarity = TIM_OCPOLARITY_HIGH;
  sConfigOC.OCFastMode = TIM_OCFAST_DISABLE;
  HAL_TIM_PWM_ConfigChannel(&htim3, &sConfigOC, TIM_CHANNEL_1);
  HAL_TIM_PWM_Start(&htim3, TIM_CHANNEL_1);
}

void Set_ESC_Throttle(uint16_t pulse_us) {
  // pulse_us: 1000 to 2000
  __HAL_TIM_SET_COMPARE(&htim3, TIM_CHANNEL_1, pulse_us);
}

int main() {
  HAL_Init();
  SystemClock_Config();
  TIM3_PWM_Init();

  Set_ESC_Throttle(1000); // Arm
  HAL_Delay(2000);
  Set_ESC_Throttle(1300); // 30% throttle

  while (1) {}
}
