```c
// X-configuration motor layout:
//   M1(CCW) --- M2(CW)
//       \       /
//        \     /
//       M4(CW)--M3(CCW)

void motor_mix(float throttle, float roll, float pitch, float yaw,
               int *m1, int *m2, int *m3, int *m4) {
  // throttle, roll, pitch, yaw all in range -1.0 to 1.0
  // throttle: 0.0 to 1.0

  float base = throttle * 1000.0f + 1000.0f;

  *m1 = (int)(base - roll + pitch - yaw); // Front-left  CCW
  *m2 = (int)(base + roll + pitch + yaw); // Front-right CW
  *m3 = (int)(base + roll - pitch - yaw); // Rear-right  CCW
  *m4 = (int)(base - roll - pitch + yaw); // Rear-left   CW

  // Clamp to valid ESC range
  *m1 = (*m1 < 1000) ? 1000 : (*m1 > 2000) ? 2000 : *m1;
  *m2 = (*m2 < 1000) ? 1000 : (*m2 > 2000) ? 2000 : *m2;
  *m3 = (*m3 < 1000) ? 1000 : (*m3 > 2000) ? 2000 : *m3;
  *m4 = (*m4 < 1000) ? 1000 : (*m4 > 2000) ? 2000 : *m4;
}
```
Yaw control works because diagonal motors spin in opposite directions. CW motors contribute +yaw, CCW motors contribute -yaw to rotation torque.

```c
#include <avr/io.h>
#include <util/delay.h>

void pwm_init() {
  // Timer1 Fast PWM, non-inverting, prescaler 8
  // 16MHz / 8 / 40000 = 50Hz
  TCCR1A = (1 << COM1A1) | (1 << WGM11);
  TCCR1B = (1 << WGM13) | (1 << WGM12) | (1 << CS11); // Prescaler 8
  ICR1 = 39999; // TOP value: 50Hz period
  OCR1A = 1999; // 1ms pulse = min throttle (1000us / 0.5us = 2000 counts, -1)
  DDRB |= (1 << PB1); // OC1A pin as output
}

void set_throttle_us(uint16_t us) {
  // us: 1000 to 2000
  OCR1A = (us * 2) - 1; // 0.5us resolution at 16MHz/8
}

int main() {
  pwm_init();
  set_throttle_us(1000);
  _delay_ms(2000); // Arming
  set_throttle_us(1300);
  while (1) {}
}
```
Timer1 ICR1 sets the PWM period. At 16MHz with prescaler 8, each tick = 0.5µs. ICR1=39999 gives exactly 20ms (50Hz). OCR1A sets pulse width.

```c
#include <math.h>

#define ALPHA 0.98f  // Trust gyro 98%, accel 2%

float pitch_angle = 0.0f;

float complementary_filter(float accel_x, float accel_z, float gyro_y_dps, float dt) {
  // Accelerometer angle (degrees)
  float accel_pitch = atan2f(accel_x, accel_z) * (180.0f / M_PI);

  // Gyroscope integration
  pitch_angle = ALPHA * (pitch_angle + gyro_y_dps * dt) + (1.0f - ALPHA) * accel_pitch;

  return pitch_angle;
}

// Example usage in main loop:
// float dt = 0.004f; // 250Hz
// float pitch = complementary_filter(ax, az, gy, dt);
```
The complementary filter is lightweight and sufficient for most hobby drones. ALPHA=0.98 works well for stable flight. Reduce ALPHA if you need faster response to accelerometer data. For better accuracy use a Kalman or Madgwick filter instead.

