```c
#include <math.h>
#include <stdint.h>

// ---- PID Structure ----
typedef struct { float kp, ki, kd, integral, prev_error, limit; } PID;

float pid_compute(PID *p, float sp, float meas, float dt) {
  float e = sp - meas;
  p->integral += e * dt;
  if (p->integral >  p->limit) p->integral =  p->limit;
  if (p->integral < -p->limit) p->integral = -p->limit;
  float d = (e - p->prev_error) / dt;
  p->prev_error = e;
  return p->kp * e + p->ki * p->integral + p->kd * d;
}

// ---- Sensor Data (fill from I2C driver) ----
typedef struct { float ax, ay, az, gx, gy, gz; } IMU_Data;

// ---- Angle Estimation ----
float roll_angle = 0, pitch_angle = 0;
#define ALPHA 0.98f

void update_angles(IMU_Data *imu, float dt) {
  float accel_roll  = atan2f(imu->ay, imu->az) * (180.0f / M_PI);
  float accel_pitch = atan2f(imu->ax, imu->az) * (180.0f / M_PI);
  roll_angle  = ALPHA * (roll_angle  + imu->gx * dt) + (1-ALPHA) * accel_roll;
  pitch_angle = ALPHA * (pitch_angle + imu->gy * dt) + (1-ALPHA) * accel_pitch;
}

// ---- Motor Mix ----
void motor_mix(float thr, float roll, float pitch, float yaw,
               uint16_t *m1, uint16_t *m2, uint16_t *m3, uint16_t *m4) {
  int base = (int)(thr * 1000.0f) + 1000;
  *m1 = (uint16_t)fmaxf(1000, fminf(2000, base - roll + pitch - yaw));
  *m2 = (uint16_t)fmaxf(1000, fminf(2000, base + roll + pitch + yaw));
  *m3 = (uint16_t)fmaxf(1000, fminf(2000, base + roll - pitch - yaw));
  *m4 = (uint16_t)fmaxf(1000, fminf(2000, base - roll - pitch + yaw));
}

// ---- Main Loop (called at 250Hz from timer ISR) ----
void flight_loop(float dt) {
  static PID roll_pid  = {1.5f, 0.03f, 0.8f, 0, 0, 400};
  static PID pitch_pid = {1.5f, 0.03f, 0.8f, 0, 0, 400};
  static PID yaw_pid   = {3.0f, 0.01f, 0.2f, 0, 0, 200};

  IMU_Data imu;
  // imu_read(&imu);  // Fill from your I2C driver

  update_angles(&imu, dt);

  float rc_throttle = 0.4f; // From RC receiver (0-1)
  float rc_roll     = 0.0f; // Setpoint in degrees
  float rc_pitch    = 0.0f;
  float rc_yaw      = 0.0f;

  float roll_out  = pid_compute(&roll_pid,  rc_roll,  roll_angle,  dt);
  float pitch_out = pid_compute(&pitch_pid, rc_pitch, pitch_angle, dt);
  float yaw_out   = pid_compute(&yaw_pid,   rc_yaw,   imu.gz,     dt);

  uint16_t m1, m2, m3, m4;
  motor_mix(rc_throttle, roll_out, pitch_out, yaw_out, &m1, &m2, &m3, &m4);

  // set_motor_pwm(m1, m2, m3, m4);  // Your HAL PWM output here
}
```
This is a real-world usable skeleton. Replace `imu_read()` and `set_motor_pwm()` with your actual STM32 HAL I2C and TIM calls. Run `flight_loop()` from a 250Hz timer interrupt for stable operation.

```cpp
#include <driver/rmt.h>

#define DSHOT_GPIO    13
#define RMT_CHANNEL   RMT_CHANNEL_0
#define DSHOT_CLK_DIV 8
// At 80MHz APB clock / 8 = 10MHz, 0.1µs resolution
// DSHOT300: bit period = 3.33µs → 33 ticks
// 1-bit: HIGH for 24 ticks, LOW for 9 ticks
// 0-bit: HIGH for 12 ticks, LOW for 21 ticks

void dshot_init() {
  rmt_config_t config = {};
  config.rmt_mode = RMT_MODE_TX;
  config.channel = RMT_CHANNEL;
  config.gpio_num = (gpio_num_t)DSHOT_GPIO;
  config.clk_div = DSHOT_CLK_DIV;
  config.mem_block_num = 1;
  config.tx_config.loop_en = false;
  config.tx_config.carrier_en = false;
  config.tx_config.idle_output_en = true;
  config.tx_config.idle_level = RMT_IDLE_LEVEL_LOW;
  rmt_config(&config);
  rmt_driver_install(RMT_CHANNEL, 0, 0);
}

void dshot_send(uint16_t throttle, bool telemetry) {
  // throttle: 0 (disarmed) or 48–2047
  uint16_t packet = (throttle << 1) | (telemetry ? 1 : 0);

  // CRC
  uint8_t crc = (packet ^ (packet >> 4) ^ (packet >> 8)) & 0x0F;
  packet = (packet << 4) | crc;

  rmt_item32_t items[16];
  for (int i = 15; i >= 0; i--) {
    bool bit = (packet >> i) & 1;
    items[15 - i].duration0 = bit ? 24 : 12;
    items[15 - i].level0 = 1;
    items[15 - i].duration1 = bit ? 9 : 21;
    items[15 - i].level1 = 0;
  }

  rmt_write_items(RMT_CHANNEL, items, 16, true);
}

void setup() {
  dshot_init();
}

void loop() {
  dshot_send(0, false);   // Disarmed
  delay(1000);
  dshot_send(300, false); // ~15% throttle
  delay(5000);
}
```
DSHOT advantages over PWM: no calibration required, digital CRC-protected frames, no analog noise, supports bidirectional telemetry. DSHOT300 is a safe starting point — DSHOT600 requires tighter timing.

