#include <ESP32Servo.h>

Servo esc1, esc2, esc3, esc4;

unsigned long last_command_time = 0;
const unsigned long FAILSAFE_TIMEOUT = 500; // ms
bool failsafe_active = false;

void arm_escs() {
  esc1.writeMicroseconds(1000);
  esc2.writeMicroseconds(1000);
  esc3.writeMicroseconds(1000);
  esc4.writeMicroseconds(1000);
}

void cut_motors() {
  esc1.writeMicroseconds(900); // Below arm threshold
  esc2.writeMicroseconds(900);
  esc3.writeMicroseconds(900);
  esc4.writeMicroseconds(900);
  failsafe_active = true;
  Serial.println("FAILSAFE ACTIVATED");
}

void set_throttle(int val) {
  last_command_time = millis();
  failsafe_active = false;
  int t = constrain(val, 1000, 2000);
  esc1.writeMicroseconds(t);
  esc2.writeMicroseconds(t);
  esc3.writeMicroseconds(t);
  esc4.writeMicroseconds(t);
}

void check_failsafe() {
  if (!failsafe_active && (millis() - last_command_time > FAILSAFE_TIMEOUT)) {
    cut_motors();
  }
}

void setup() {
  Serial.begin(115200);
  esc1.attach(13, 1000, 2000);
  esc2.attach(14, 1000, 2000);
  esc3.attach(25, 1000, 2000);
  esc4.attach(26, 1000, 2000);
  arm_escs();
  delay(3000);
  last_command_time = millis();
}

void loop() {
  check_failsafe(); // Call every loop iteration
  // Your command handling here
}
```
Failsafe is non-negotiable safety infrastructure. A drone that loses connection and keeps flying is a weapon. 500ms is standard — match it to your control loop latency.

```cpp
#include <Arduino.h>

#define CH1_PIN 2  // Throttle
#define CH2_PIN 3  // Roll
#define CH3_PIN 4  // Pitch
#define CH4_PIN 5  // Yaw

volatile unsigned long ch1_start, ch2_start, ch3_start, ch4_start;
volatile int ch1_val = 1000, ch2_val = 1500, ch3_val = 1500, ch4_val = 1500;

void ch1_isr() {
  if (digitalRead(CH1_PIN)) ch1_start = micros();
  else ch1_val = micros() - ch1_start;
}
void ch2_isr() {
  if (digitalRead(CH2_PIN)) ch2_start = micros();
  else ch2_val = micros() - ch2_start;
}
void ch3_isr() {
  if (digitalRead(CH3_PIN)) ch3_start = micros();
  else ch3_val = micros() - ch3_start;
}
void ch4_isr() {
  if (digitalRead(CH4_PIN)) ch4_start = micros();
  else ch4_val = micros() - ch4_start;
}

void setup() {
  Serial.begin(115200);
  pinMode(CH1_PIN, INPUT);
  pinMode(CH2_PIN, INPUT);
  pinMode(CH3_PIN, INPUT);
  pinMode(CH4_PIN, INPUT);

  attachInterrupt(digitalPinToInterrupt(CH1_PIN), ch1_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(CH2_PIN), ch2_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(CH3_PIN), ch3_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(CH4_PIN), ch4_isr, CHANGE);
}

void loop() {
  Serial.printf("THR:%d ROL:%d PIT:%d YAW:%d\n", ch1_val, ch2_val, ch3_val, ch4_val);
  delay(100);
}
```
The CHANGE interrupt fires on both rising and falling edges. Rising edge = start timer, falling edge = measure pulse width. Values should range 1000–2000µs. Values outside 900–2100µs indicate signal loss or bad wiring.

