```c
#include <avr/io.h>
#include <util/twi.h>

#define F_CPU     16000000UL
#define SCL_CLOCK 100000UL
#define TWBR_VAL  ((F_CPU / SCL_CLOCK - 16) / 2)  // = 72

// Initialize TWI
void twi_init(void) {
    TWSR = 0x00;           // Prescaler = 1 (TWPS1:TWPS0 = 00)
    TWBR = (uint8_t)TWBR_VAL;  // Bit rate register
    TWCR = (1 << TWEN);    // Enable TWI module
}

// Send START condition
uint8_t twi_start(uint8_t address) {
    // Send START
    TWCR = (1 << TWINT) | (1 << TWSTA) | (1 << TWEN);
    while (!(TWCR & (1 << TWINT)));  // Wait for completion
    if ((TWSR & 0xF8) != TW_START) return 1;  // Error

    // Send device address + R/W bit
    TWDR = address;
    TWCR = (1 << TWINT) | (1 << TWEN);
    while (!(TWCR & (1 << TWINT)));
    uint8_t status = TWSR & 0xF8;
    if (status != TW_MT_SLA_ACK && status != TW_MR_SLA_ACK) return 2;
    return 0;
}

// Send STOP condition
void twi_stop(void) {
    TWCR = (1 << TWINT) | (1 << TWSTO) | (1 << TWEN);
    while (TWCR & (1 << TWSTO));  // Wait for STOP to complete
}

// Write one byte
uint8_t twi_write(uint8_t data) {
    TWDR = data;
    TWCR = (1 << TWINT) | (1 << TWEN);
    while (!(TWCR & (1 << TWINT)));
    return (TWSR & 0xF8) != TW_MT_DATA_ACK;
}

// Read byte with ACK
uint8_t twi_read_ack(void) {
    TWCR = (1 << TWINT) | (1 << TWEN) | (1 << TWEA);
    while (!(TWCR & (1 << TWINT)));
    return TWDR;
}

// Read byte with NACK (last byte)
uint8_t twi_read_nack(void) {
    TWCR = (1 << TWINT) | (1 << TWEN);
    while (!(TWCR & (1 << TWINT)));
    return TWDR;
}

// Example: Read 2 bytes from register 0x3B of device 0x68 (MPU-6050)
int main(void) {
    twi_init();
    uint8_t data[2];

    // Write register address
    twi_start((0x68 << 1) | TW_WRITE);  // Address + WRITE
    twi_write(0x3B);                     // Register pointer
    twi_stop();

    // Read 2 bytes
    twi_start((0x68 << 1) | TW_READ);   // Address + READ
    data[0] = twi_read_ack();
    data[1] = twi_read_nack();           // Last byte: send NACK
    twi_stop();

    while(1);
    return 0;
}
```

Register Breakdown:
- TWBR: Bit Rate Register → controls SCL frequency
  SCL = F_CPU / (16 + 2×TWBR×Prescaler)
- TWSR: Status Register
  - Bits 7:3 = Status code (masked with 0xF8)
  - Bits 1:0 = Prescaler select
- TWCR: Control Register
  - TWEN=1: Enable TWI
  - TWINT=1: Clear interrupt flag (write 1 to clear!)
  - TWSTA=1: Generate START
  - TWSTO=1: Generate STOP
  - TWEA=1: Send ACK after receiving

