```c
#include <avr/io.h>

// SPI Pin Definitions (ATmega328P hardware SPI)
// MOSI = PB3, MISO = PB4, SCK = PB5, SS = PB2

void spi_init_master(void) {
    // Set MOSI, SCK, SS as outputs; MISO as input
    DDRB |= (1 << DDB3)   // MOSI
          | (1 << DDB5)   // SCK
          | (1 << DDB2);  // SS (chip select)
    DDRB &= ~(1 << DDB4); // MISO as INPUT

    // Drive SS HIGH (deselect slave)
    PORTB |= (1 << PORTB2);

    // SPCR: SPI Control Register
    // SPE  = 1 → Enable SPI
    // MSTR = 1 → Master mode
    // SPR1=0, SPR0=0 → Clock = F_CPU/4 = 4MHz  (with SPI2X=0)
    // For 1MHz: set SPR1=0, SPR0=1 → F_CPU/16 = 1MHz
    SPCR = (1 << SPE)    // SPI Enable
         | (1 << MSTR)   // Master
         | (1 << SPR0);  // Prescaler /16 → 1MHz

    SPSR = 0;  // SPI2X=0 (no double speed)
}

uint8_t spi_transfer(uint8_t data) {
    PORTB &= ~(1 << PORTB2);  // CS LOW → select slave
    SPDR = data;              // Load data into SPI Data Register
    while (!(SPSR & (1 << SPIF)));  // Wait for SPIF (transfer complete)
    PORTB |= (1 << PORTB2);   // CS HIGH → deselect slave
    return SPDR;               // Return received byte
}

void spi_send_buffer(uint8_t *buf, uint8_t len) {
    PORTB &= ~(1 << PORTB2);  // CS LOW
    for (uint8_t i = 0; i < len; i++) {
        SPDR = buf[i];
        while (!(SPSR & (1 << SPIF)));
    }
    PORTB |= (1 << PORTB2);   // CS HIGH
}

int main(void) {
    spi_init_master();

    uint8_t tx_data = 0xAB;
    uint8_t rx_data = spi_transfer(tx_data);
    (void)rx_data;  // Use received data as needed

    uint8_t buffer[] = {0x01, 0x02, 0x03, 0x04};
    spi_send_buffer(buffer, 4);

    while(1);
    return 0;
}
```

