// ─── METHOD 2: Manual Register Access ────────────────────────────
void eeprom_write_manual(uint16_t addr, uint8_t data) {
    while (EECR & (1 << EEPE));    // Wait for previous write to finish
    cli();                          // Disable interrupts (critical section)
    EEAR = addr;                    // Set address register
    EEDR = data;                    // Set data register
    EECR |= (1 << EEMPE);          // Master Write Enable (must be set first)
    EECR |= (1 << EEPE);           // Start write (within 4 cycles of EEMPE)
    sei();                          // Re-enable interrupts
}

uint8_t eeprom_read_manual(uint16_t addr) {
    while (EECR & (1 << EEPE));    // Wait for any write in progress
    EEAR = addr;                    // Set address
    EECR |= (1 << EERE);           // Start read
    return EEDR;                    // Return data (available immediately)
}

// ─── MAIN ─────────────────────────────────────────────────────────
int main(void) {
    // Store a configuration byte
    uint8_t config = 0xA5;
    eeprom_write_manual(0x00, config);

    // Read it back
    uint8_t read_val = eeprom_read_manual(0x00);
    (void)read_val;

    while(1);
    return 0;
}
