#include <avr/io.h>
#include <avr/wdt.h>
#include <avr/interrupt.h>
#include <util/delay.h>

// Watchdog ISR (if using interrupt mode instead of reset)
ISR(WDT_vect) {
    // This fires INSTEAD of reset if WDIE=1, WDCE=1
    // Use for safe shutdown before reset
    PORTB |= (1 << PORTB5);  // Signal WDT event
}

void wdt_init_reset_mode(void) {
    // IMPORTANT: Must disable interrupts during WDT configuration
    cli();

    // Step 1: Enable write access to WDTCSR
    WDTCSR |= (1 << WDCE) | (1 << WDE);

    // Step 2: Set desired timeout — must happen within 4 clock cycles!
    // WDP3:WDP0 timeout selection:
    // 0000 = 16ms
    // 0001 = 32ms
    // 0010 = 64ms
    // 0011 = 125ms
    // 0100 = 250ms
    // 0101 = 500ms
    // 0110 = 1s
    // 0111 = 2s  ← We want this
    // 1000 = 4s
    // 1001 = 8s
    WDTCSR = (1 << WDE)      // Enable reset mode
           | (1 << WDP2)     // WDP2=1
           | (1 << WDP1)     // WDP1=1
           | (1 << WDP0);    // WDP0=1 → 2 second timeout

    sei();
}

void wdt_reset_timer(void) {
    wdt_reset();  // "pat" the watchdog — prevents reset
    // Equivalent to: asm volatile ("wdr");
}

int main(void) {
    DDRB |= (1 << DDB5);     // LED for indication

    wdt_init_reset_mode();   // 2-second WDT reset

    uint8_t counter = 0;

    while (1) {
        _delay_ms(500);
        PORTB ^= (1 << PORTB5);  // Blink LED
        counter++;

        if (counter < 5) {
            wdt_reset_timer();   // Keep resetting WDT (system OK)
        }
        // After ~2.5s without reset, WDT will trigger MCU reset
        // Counter >= 5 → WDT fires → MCU resets → LED pattern restarts
    }
    return 0;
}
