```c
#include <avr/io.h>
#include <avr/interrupt.h>
#include <util/delay.h>

#define F_CPU 16000000UL

// PID Constants (tune these for your motor)
#define KP  2.0f
#define KI  0.5f
#define KD  0.1f

#define SETPOINT   512    // Desired ADC value (0–1023)
#define PWM_MAX    1023   // Timer1 10-bit TOP

volatile uint16_t adc_value = 0;

// ─── ADC ──────────────────────────────────────────
void adc_init(void) {
    ADMUX  = (1 << REFS0);                          // AVCC reference
    ADCSRA = (1 << ADEN) | (1 << ADIE)             // Enable + interrupt
           | (1 << ADPS2) | (1 << ADPS1) | (1 << ADPS0); // /128 prescaler
}

void adc_start(void) {
    ADCSRA |= (1 << ADSC);  // Start conversion
}

ISR(ADC_vect) {
    adc_value = ADC;         // Store 10-bit result
    adc_start();             // Start next conversion (free-running)
}

// ─── PWM (Timer1, 10-bit Fast PWM on OC1A) ────────
void pwm_init(void) {
    DDRB |= (1 << DDB1);      // OC1A as output

    // WGM13:WGM10 = 0111 → 10-bit Fast PWM, TOP = 0x03FF = 1023
    TCCR1A = (1 << COM1A1)   // Non-inverting OC1A
           | (1 << WGM11)    // WGM11=1
           | (1 << WGM10);   // WGM10=1 → 10-bit fast PWM
    TCCR1B = (1 << WGM12)    // WGM12=1
           | (1 << CS11);    // Prescaler /8 → PWM ≈ 7.8kHz
    OCR1A  = 0;               // Start at 0% duty
}

void pwm_set(int16_t duty) {
    if (duty < 0)    duty = 0;
    if (duty > PWM_MAX) duty = PWM_MAX;
    OCR1A = (uint16_t)duty;
}

// ─── PID Controller ───────────────────────────────
float pid_update(uint16_t setpoint, uint16_t measurement) {
    static float integral   = 0.0f;
    static float prev_error = 0.0f;

    float error      = (float)setpoint - (float)measurement;
    integral        += error;
    float derivative = error - prev_error;
    prev_error       = error;

    // Anti-windup: clamp integral
    if (integral >  1000.0f) integral =  1000.0f;
    if (integral < -1000.0f) integral = -1000.0f;

    return (KP * error) + (KI * integral) + (KD * derivative);
}

// ─── MAIN ─────────────────────────────────────────
int main(void) {
    adc_init();
    pwm_init();
    sei();
    adc_start();  // Start first conversion

    while (1) {
        float output = pid_update(SETPOINT, adc_value);
        pwm_set((int16_t)output);
        _delay_ms(10);  // 100Hz control loop
    }
    return 0;
}
```

PID Concept:
- Error = Setpoint − Measured
- P term: Proportional to current error → fast response
- I term: Accumulated error over time → eliminates steady-state error
- D term: Rate of error change → dampens oscillation

Tuning Procedure:
1. Set KI=0, KD=0, increase KP until oscillation
2. Reduce KP by 50%
3. Increase KI slowly to eliminate steady-state offset
4. Increase KD to reduce overshoot

