#include <avr/io.h>
#include <avr/interrupt.h>

volatile uint8_t portb_last = 0xFF;

// PCINT0_vect fires for ANY change on PB0–PB7
ISR(PCINT0_vect) {
    uint8_t portb_now   = PINB;
    uint8_t changed     = portb_now ^ portb_last;   // Which pins changed?
    uint8_t falling     = portb_last & ~portb_now;   // Which went HIGH→LOW?
    uint8_t rising      = ~portb_last & portb_now;   // Which went LOW→HIGH?

    // Check individual pins
    if (changed & (1 << PINB0)) {
        if (falling & (1 << PINB0)) {
            // PB0 went LOW (button pressed if pull-up)
            PORTD |= (1 << PORTD0);   // Signal on PD0
        } else {
            // PB0 went HIGH (button released)
            PORTD &= ~(1 << PORTD0);
        }
    }

    if (changed & (1 << PINB1)) {
        // PB1 changed state
        PORTD ^= (1 << PORTD1);  // Toggle PD1
    }

    portb_last = portb_now;  // Update last state
}

int main(void) {
    // Configure PB0, PB1 as inputs with pull-ups
    DDRB  &= ~((1 << DDB0) | (1 << DDB1));
    PORTB |=  ((1 << PORTB0) | (1 << PORTB1));

    // Configure PD0, PD1 as outputs (indicators)
    DDRD |= (1 << DDD0) | (1 << DDD1);

    // PCICR: Pin Change Interrupt Control Register
    // PCIE0 → enable PCINT0 group (PB0–PB7)
    // PCIE1 → enable PCINT1 group (PC0–PC6)
    // PCIE2 → enable PCINT2 group (PD0–PD7)
    PCICR |= (1 << PCIE0);    // Enable PCINT0 group

    // PCMSK0: Pin Change Mask Register 0
    // Each bit enables/disables that specific pin in the group
    PCMSK0 = (1 << PCINT0)    // PB0
           | (1 << PCINT1);   // PB1
    // To enable all PB pins: PCMSK0 = 0xFF;

    portb_last = PINB;  // Initialize state
    sei();              // Enable global interrupts

    while(1) {
        // Main loop free to do other work
        // Pin changes handled in ISR
    }
    return 0;
}
```

