// RTC time structure
volatile struct {
    uint8_t seconds;
    uint8_t minutes;
    uint8_t hours;
} rtc = {0, 0, 0};

ISR(TIMER2_OVF_vect) {
    // 32768 Hz / 128 (prescaler) = 256 Hz
    // Timer overflows at 256 counts → 1 Hz tick
    rtc.seconds++;
    if (rtc.seconds >= 60) {
        rtc.seconds = 0;
        rtc.minutes++;
        if (rtc.minutes >= 60) {
            rtc.minutes = 0;
            rtc.hours++;
            if (rtc.hours >= 24) {
                rtc.hours = 0;
            }
        }
    }
}

void rtc_init(void) {
    // Disable Timer2 before reconfiguring
    TCCR2B = 0;

    // Step 1: Switch to asynchronous mode
    // AS2=1 → Timer2 clocked from TOSC1 pin (external 32.768 kHz crystal)
    ASSR = (1 << AS2);

    // Step 2: Configure Timer2
    TCNT2  = 0;               // Reset counter
    TCCR2A = 0x00;            // Normal mode
    TCCR2B = (1 << CS22) | (1 << CS20); // Prescaler /128
    // 32768 / 128 = 256 Hz → overflow every 256 counts = 1 Hz

    // Step 3: Wait for async registers to update
    // ASSR status bits clear when update is complete
    while (ASSR & ((1 << TCN2UB) | (1 << TCR2BUB)));

    // Step 4: Enable overflow interrupt
    TIMSK2 = (1 << TOIE2);

    // Step 5: Clear any pending interrupt flag
    TIFR2 = (1 << TOV2);
}

void rtc_get_time(uint8_t *h, uint8_t *m, uint8_t *s) {
    cli();
    *h = rtc.hours;
    *m = rtc.minutes;
    *s = rtc.seconds;
    sei();
}

int main(void) {
