    sei();

    uint8_t last_sec = 0;
    while (1) {
        uint8_t h, m, s;
        rtc_get_time(&h, &m, &s);

        if (s != last_sec) {
            PORTB ^= (1 << PORTB5);  // Toggle LED each second
            last_sec = s;
            // Here you would update a display: HH:MM:SS
        }
    }
    return 0;
}
