#include <avr/io.h>
#include <util/delay.h>

// Keypad layout
const char keys[4][4] = {
    {'1', '2', '3', 'A'},
    {'4', '5', '6', 'B'},
    {'7', '8', '9', 'C'},
    {'*', '0', '#', 'D'}
};

// Row pins: PD4, PD5, PD6, PD7
// Col pins: PC0, PC1, PC2, PC3

void keypad_init(void) {
    // Rows: PD4–PD7 as OUTPUTS, start HIGH
    DDRD  |= (0xF0);         // 0b11110000 → PD4–PD7 output
    PORTD |= (0xF0);         // Drive rows HIGH

    // Columns: PC0–PC3 as INPUTS with pull-ups
    DDRC  &= ~(0x0F);        // 0b00001111 cleared → PC0–PC3 input
    PORTC |= (0x0F);         // Enable pull-ups on columns
}

char keypad_scan(void) {
    for (uint8_t row = 0; row < 4; row++) {
        // Pull current row LOW, keep others HIGH
        PORTD = (0xF0) & ~(1 << (row + 4));

        _delay_us(10);  // Settle time

        // Check each column
        for (uint8_t col = 0; col < 4; col++) {
            if (!(PINC & (1 << col))) {  // Column pulled LOW = key pressed
                _delay_ms(20);           // Debounce
                if (!(PINC & (1 << col))) {
                    // Wait for key release
                    while (!(PINC & (1 << col)));
                    _delay_ms(20);
                    return keys[row][col];
                }
            }
        }
    }
    PORTD |= 0xF0;  // Restore all rows HIGH
    return 0;       // No key pressed
}

// UART for displaying key presses
void uart_init(void) {
    UBRR0L = 103;
    UCSR0B = (1 << TXEN0);
    UCSR0C = (1 << UCSZ01) | (1 << UCSZ00);
}

void uart_putchar(char c) {
    while (!(UCSR0A & (1 << UDRE0)));
    UDR0 = c;
}

int main(void) {
    keypad_init();
    uart_init();

    while (1) {
        char key = keypad_scan();
        if (key) {
            uart_putchar(key);
            uart_putchar('\r');
            uart_putchar('\n');
        }
    }
    return 0;
}
```

Scanning Principle:
1. Set one row LOW at a time (active-low drive)
2. Read all column pins
3. If a column reads LOW → that row/column intersection is pressed
4. Key identity = keys[row][col]

PORTD bit patterns during scan:
Row 0 active: PORTD = 0b11100000  (PD4 LOW)
Row 1 active: PORTD = 0b11010000  (PD5 LOW)
Row 2 active: PORTD = 0b10110000  (PD6 LOW)
Row 3 active: PORTD = 0b01110000  (PD7 LOW)

