#include <avr/sleep.h>
#include <avr/interrupt.h>
#include <avr/power.h>

// Wake up on INT0 (PD2) press
ISR(INT0_vect) {
    // Waking up — do nothing here, or handle event
}

void enter_power_down(void) {
    // Optional: Disable unused peripherals to save more power
    power_adc_disable();     // Disable ADC
    power_spi_disable();     // Disable SPI
    power_twi_disable();     // Disable TWI
    power_timer0_disable();  // Disable Timer0
    power_timer1_disable();  // Disable Timer1
    power_timer2_disable();  // Disable Timer2
    power_usart0_disable();  // Disable USART

    set_sleep_mode(SLEEP_MODE_PWR_DOWN);  // Choose mode
    sleep_enable();           // Set SE bit
    sei();                    // Make sure interrupts are on
    sleep_cpu();              // Execute SLEEP instruction
    // ↑ CPU halts here until interrupt fires
    // ↓ Execution resumes here after wake-up
    sleep_disable();          // Clear SE bit (best practice)

    // Re-enable peripherals
    power_all_enable();
}

void setup_wakeup_interrupt(void) {
    DDRD  &= ~(1 << DDD2);   // PD2 as input
    PORTD |=  (1 << PORTD2); // Pull-up
    EICRA  =  (1 << ISC01);  // Falling edge
    EIMSK  =  (1 << INT0);   // Enable INT0
}

int main(void) {
    setup_wakeup_interrupt();
    DDRB |= (1 << DDB5);     // LED output

    while (1) {
        // Blink LED to show system is awake
        PORTB |= (1 << PORTB5);
        for (volatile long i = 0; i < 100000; i++);
        PORTB &= ~(1 << PORTB5);
        for (volatile long i = 0; i < 100000; i++);

        // Go to sleep
        enter_power_down();
        // Woken by button press on INT0
    }
    return 0;
}
```

Power Reduction Tips:
1. Disable unused peripherals via PRR register
2. Reduce clock speed (CLKPR register, software prescaler)
3. Use Power-down for maximum saving (everything off except WDT)
4. Avoid floating input pins (enable pull-ups or connect to known state)
5. Minimize time in active mode — do work quickly, sleep the rest

