#define F_CPU 16000000UL

// Servo PWM:
// Period = 20ms (50Hz)
// Min pulse = 1ms (0 degrees)
// Max pulse = 2ms (180 degrees)
// Timer1 with ICR1 as TOP (Mode 14: Fast PWM)

// Prescaler = 8 → Timer clock = 2MHz → 1 tick = 0.5µs
// 20ms period = 40000 ticks → ICR1 = 39999
// 1ms  pulse  =  2000 ticks
// 2ms  pulse  =  4000 ticks

#define SERVO_TOP   39999
#define SERVO_MIN   2000    // 1.0ms → 0 degrees
#define SERVO_MID   3000    // 1.5ms → 90 degrees
#define SERVO_MAX   4000    // 2.0ms → 180 degrees

void servo_init(void) {
    DDRB |= (1 << DDB1);  // OC1A as output

    // Timer1 Fast PWM, TOP = ICR1 (Mode 14)
    // WGM13=1, WGM12=1, WGM11=1, WGM10=0
    TCCR1A = (1 << COM1A1)   // Non-inverting on OC1A
           | (1 << WGM11);   // WGM11=1
    TCCR1B = (1 << WGM13)    // WGM13=1
           | (1 << WGM12)    // WGM12=1
           | (1 << CS11);    // Prescaler /8

    ICR1  = SERVO_TOP;        // TOP = 39999 → 20ms period
    OCR1A = SERVO_MID;        // Start at 90 degrees
}

// Set servo angle (0–180 degrees)
void servo_set_angle(uint8_t angle) {
    if (angle > 180) angle = 180;
    // Map 0–180 → SERVO_MIN–SERVO_MAX
    uint16_t pulse = SERVO_MIN + ((uint32_t)angle * (SERVO_MAX - SERVO_MIN)) / 180;
    OCR1A = pulse;
}

// Set servo position directly in microseconds (1000–2000µs)
void servo_set_us(uint16_t us) {
    if (us < 1000) us = 1000;
    if (us > 2000) us = 2000;
    OCR1A = us * 2;  // 1 tick = 0.5µs → multiply by 2
}

int main(void) {
    servo_init();

    while (1) {
        // Sweep 0 to 180 degrees
        for (int angle = 0; angle <= 180; angle += 5) {
            servo_set_angle(angle);
            _delay_ms(50);
        }
        // Sweep 180 to 0 degrees
        for (int angle = 180; angle >= 0; angle -= 5) {
            servo_set_angle(angle);
            _delay_ms(50);
        }
    }
    return 0;
}
```

PWM Timing Breakdown:
At 16MHz, prescaler /8 → tick = 0.5µs
ICR1 = 39999 → period = 40000 × 0.5µs = 20ms = 50Hz ✅
OCR1A = 2000 → pulse = 2000 × 0.5µs = 1.0ms → 0° ✅
OCR1A = 3000 → pulse = 3000 × 0.5µs = 1.5ms → 90° ✅
OCR1A = 4000 → pulse = 4000 × 0.5µs = 2.0ms → 180° ✅

Timer1 Mode 14 (Fast PWM, TOP=ICR1):
WGM13 | WGM12 | WGM11 | WGM10
  1   |   1   |   1   |   0
Counter goes 0 → ICR1, then resets
OCR1A sets when output goes LOW (non-inverting)

```c
#include <avr/io.h>
#include <avr/interrupt.h>
#include <stdint.h>

#define F_CPU 16000000UL
#define BAUD  9600
#define UBRR_VAL ((F_CPU / (16UL * BAUD)) - 1)

// ─── Circular Buffer ──────────────────────────────────────
#define RX_BUFFER_SIZE 64  // Must be power of 2!
#define RX_BUFFER_MASK (RX_BUFFER_SIZE - 1)

typedef struct {
    volatile uint8_t  buf[RX_BUFFER_SIZE];
    volatile uint8_t  head;   // Write index (ISR writes here)
    volatile uint8_t  tail;   // Read  index (main code reads here)
} ring_buffer_t;

ring_buffer_t rx_buf = { .head = 0, .tail = 0 };

// ─── UART ISR: fires when byte received ───────────────────
ISR(USART_RX_vect) {
    uint8_t data = UDR0;  // Must read UDR0 to clear interrupt!
    uint8_t next_head = (rx_buf.head + 1) & RX_BUFFER_MASK;

    if (next_head != rx_buf.tail) {    // Buffer not full?
        rx_buf.buf[rx_buf.head] = data;
        rx_buf.head = next_head;
    }
    // If full: byte is silently dropped (add error flag if needed)
}

// ─── Buffer API ───────────────────────────────────────────
uint8_t rx_available(void) {
    return rx_buf.head != rx_buf.tail;
}

uint8_t rx_read(void) {
    // Spin-wait if empty (or check rx_available() first)
    while (!rx_available());
    uint8_t data = rx_buf.buf[rx_buf.tail];
    rx_buf.tail  = (rx_buf.tail + 1) & RX_BUFFER_MASK;
    return data;
}

uint8_t rx_buffer_count(void) {
    return (rx_buf.head - rx_buf.tail) & RX_BUFFER_MASK;
}

void rx_flush(void) {
    rx_buf.tail = rx_buf.head;  // Mark buffer empty
}

// ─── UART Init ────────────────────────────────────────────
void uart_init(void) {
    UBRR0H = (UBRR_VAL >> 8);
    UBRR0L = (UBRR_VAL & 0xFF);
    UCSR0B = (1 << RXEN0)    // Enable receiver
           | (1 << TXEN0)    // Enable transmitter
           | (1 << RXCIE0);  // Enable RX Complete interrupt
    UCSR0C = (1 << UCSZ01) | (1 << UCSZ00);  // 8N1
}

void uart_putchar(char c) {
    while (!(UCSR0A & (1 << UDRE0)));
    UDR0 = c;
}

void uart_print(const char *s) {
    while (*s) uart_putchar(*s++);
}

// ─── Main ─────────────────────────────────────────────────
int main(void) {
    uart_init();
    sei();

    uart_print("Ring Buffer UART Ready\r\n");

    while (1) {
        if (rx_available()) {
            uint8_t c = rx_read();
            uart_putchar(c);    // Echo received byte

            // Example: process newline-terminated commands
            if (c == '\n') {
                uart_print("Got newline!\r\n");
            }
        }
        // Main loop free for other work while ISR handles receiving
    }
    return 0;
}
```

Circular Buffer Mechanics:
- head: where the ISR WRITES next
- tail: where main code READS next
- Empty condition:  head == tail
- Full condition:   next_head == tail (one slot kept empty)
- Count:           (head - tail) & MASK

Why power-of-2 buffer size?
Bitwise AND wraps around without expensive modulo:
(head + 1) & 63  →  same as  (head + 1) % 64
But AND is a single clock cycle vs many for division!

input:
```c
#include <avr/io.h>
#include <util/delay.h>
#define F_CPU 16000000UL

int main(void) {
    DDRD = 0xFF;
    uint8_t pattern = 1;
    while(1) {
        PORTD = pattern;
        pattern = pattern << 1;
        _delay_ms(200);
        if(pattern == 0) pattern = 1;
    }
}
```

output:
The code logic has a SUBTLE BUG — the pattern check `if(pattern == 0)` happens AFTER the shift. When pattern = 0b10000000 (128), the shift makes it 0b100000000 = 256, which truncates to 0x00 in uint8_t. The display shows the 0x00 state for one frame before resetting.

ADDITIONAL ISSUE: `_delay_ms()` requires `#define F_CPU` BEFORE including `<util/delay.h>`. In this code, the order is correct, but it's better practice to define F_CPU in the Makefile or before any includes.

FIXED CODE (no skipped/blank step):
```c
#include <avr/io.h>
#define F_CPU 16000000UL
#include <util/delay.h>

int main(void) {
    DDRD = 0xFF;        // All Port D pins as output
    uint8_t pattern = 1;

    while (1) {
        PORTD = pattern;
        _delay_ms(200);

        // Shift THEN check — reset before it wraps to 0
        if (pattern == 0x80) {
            pattern = 0x01;    // ✅ Reset to first LED before it zeros out
        } else {
            pattern <<= 1;
        }
    }
    return 0;
}
```

ALTERNATIVE — using rotate instead of shift (wraps automatically):
```c
#include <avr/io.h>
#define F_CPU 16000000UL
#include <util/delay.h>

int main(void) {
    DDRD = 0xFF;
    uint8_t pattern = 1;

    while (1) {
        PORTD = pattern;
        _delay_ms(200);
        // Rotate left: bit 7 wraps to bit 0
        pattern = (pattern << 1) | (pattern >> 7);
    }
    return 0;
}
```

Bit rotation trace:
0b00000001 → 0b00000010 → 0b00000100 → ... → 0b10000000 → 0b00000001 (wraps!)
No blank frame, no skipped steps.

```c
#include <avr/io.h>
#include <util/delay.h>

#define F_CPU 16000000UL

// Pin definitions
#define LCD_RS  PD0
#define LCD_EN  PD1
#define LCD_D4  PD4
#define LCD_D5  PD5
#define LCD_D6  PD6
#define LCD_D7  PD7

#define LCD_PORT  PORTD
#define LCD_DDR   DDRD

// ─── Low-level helpers ───────────────────────────────────
void lcd_pulse_enable(void) {
    LCD_PORT |=  (1 << LCD_EN);  // EN HIGH
    _delay_us(1);                 // Enable pulse width ≥450ns
    LCD_PORT &= ~(1 << LCD_EN);  // EN LOW → data latched
    _delay_us(50);                // Commands need >37µs to execute
}

void lcd_send_nibble(uint8_t nibble) {
    // Map nibble bits 7:4 to PD7:PD4
    LCD_PORT &= 0x0F;            // Clear upper nibble
    LCD_PORT |= (nibble & 0xF0); // Set data bits
    lcd_pulse_enable();
}

void lcd_send_byte(uint8_t data, uint8_t is_data) {
    if (is_data) {
        LCD_PORT |=  (1 << LCD_RS);  // RS=1: Data
    } else {
        LCD_PORT &= ~(1 << LCD_RS);  // RS=0: Command
    }
    lcd_send_nibble(data & 0xF0);       // High nibble first
    lcd_send_nibble((data << 4) & 0xF0); // Low nibble
}

// ─── LCD Commands ────────────────────────────────────────
void lcd_command(uint8_t cmd)  { lcd_send_byte(cmd, 0); }
void lcd_data(uint8_t data)    { lcd_send_byte(data, 1); }

void lcd_clear(void) {
    lcd_command(0x01);   // Clear display
    _delay_ms(2);         // Clear needs 1.52ms
}

void lcd_home(void) {
    lcd_command(0x02);
    _delay_ms(2);
}

void lcd_set_cursor(uint8_t row, uint8_t col) {
    uint8_t addr = (row == 0) ? 0x00 : 0x40;  // Row 0=0x00, Row 1=0x40
    lcd_command(0x80 | (addr + col));
}

void lcd_print(const char *str) {
    while (*str) lcd_data(*str++);
}

// ─── Initialization (4-bit mode) ─────────────────────────
void lcd_init(void) {
    LCD_DDR |= (1<<LCD_RS)|(1<<LCD_EN)|(1<<LCD_D4)|(1<<LCD_D5)|(1<<LCD_D6)|(1<<LCD_D7);
    LCD_PORT = 0x00;
    _delay_ms(50);            // Wait for LCD power-up (>40ms after VCC)

    // Initialization sequence (IEEE 44780 spec, 4-bit mode entry)
    LCD_PORT &= ~(1 << LCD_RS);    // Command mode
    lcd_send_nibble(0x30);  _delay_ms(5);   // Function set (8-bit attempt 1)
    lcd_send_nibble(0x30);  _delay_us(150); // Function set (8-bit attempt 2)
    lcd_send_nibble(0x30);  _delay_us(150); // Function set (8-bit attempt 3)
    lcd_send_nibble(0x20);  _delay_us(150); // Switch to 4-bit mode

    // Now in 4-bit mode — use normal commands
    lcd_command(0x28);  // Function Set: 4-bit, 2 lines, 5×8 dots
    lcd_command(0x0C);  // Display ON, cursor OFF, blink OFF
    lcd_command(0x06);  // Entry Mode: increment cursor, no display shift
    lcd_clear();
}

// ─── Main ─────────────────────────────────────────────────
int main(void) {
    lcd_init();

    lcd_set_cursor(0, 0);
    lcd_print("Hello, AVR!");

    lcd_set_cursor(1, 0);
    lcd_print("4-bit LCD Mode");

    while(1);
    return 0;
}
```

HD44780 Key Commands:
- 0x01: Clear display
- 0x02: Return home
- 0x06: Entry mode (cursor right, no shift)
- 0x0C: Display on, cursor off
- 0x0E: Display on, cursor on
- 0x0F: Display on, cursor blinking
- 0x28: 4-bit, 2-line, 5×8 font
- 0x80 | addr: Set DDRAM address
  Row 0 starts at 0x00
  Row 1 starts at 0x40

```c
#include <avr/io.h>
#include <avr/interrupt.h>
#include <util/delay.h>

#define F_CPU 16000000UL

// LED pin definitions
#define RED_PIN    PB0
#define YELLOW_PIN PB1
#define GREEN_PIN  PB2

#define ALL_LEDS   ((1<<RED_PIN)|(1<<YELLOW_PIN)|(1<<GREEN_PIN))

// State machine states
typedef enum {
    STATE_RED,
    STATE_RED_YELLOW,  // Transition (red+yellow on together)
    STATE_GREEN,
    STATE_YELLOW,
    NUM_STATES
} TrafficState;

// Timing in milliseconds for each state
const uint16_t state_duration[NUM_STATES] = {
    [STATE_RED]        = 5000,  // Red: 5 seconds
    [STATE_RED_YELLOW] = 1000,  // Red+Yellow: 1 second
    [STATE_GREEN]      = 4000,  // Green: 4 seconds
    [STATE_YELLOW]     = 1500,  // Yellow: 1.5 seconds
};

// Output pattern for each state (which LEDs are on)
const uint8_t state_output[NUM_STATES] = {
    [STATE_RED]        = (1 << RED_PIN),
    [STATE_RED_YELLOW] = (1 << RED_PIN) | (1 << YELLOW_PIN),
    [STATE_GREEN]      = (1 << GREEN_PIN),
    [STATE_YELLOW]     = (1 << YELLOW_PIN),
};

// Next state transitions
const TrafficState next_state[NUM_STATES] = {
    [STATE_RED]        = STATE_RED_YELLOW,
    [STATE_RED_YELLOW] = STATE_GREEN,
    [STATE_GREEN]      = STATE_YELLOW,
    [STATE_YELLOW]     = STATE_RED,
};

void leds_init(void) {
    DDRB |= ALL_LEDS;
    PORTB &= ~ALL_LEDS;  // All off
}

void set_traffic_light(uint8_t pattern) {
    PORTB = (PORTB & ~ALL_LEDS) | (pattern & ALL_LEDS);
}

void delay_ms(uint16_t ms) {
    while (ms--) _delay_ms(1);
}

int main(void) {
    leds_init();

    TrafficState current_state = STATE_RED;

    while (1) {
        // Set output for current state
        set_traffic_light(state_output[current_state]);

        // Hold for state duration
        delay_ms(state_duration[current_state]);

        // Transition to next state
        current_state = next_state[current_state];
    }
    return 0;
}
