PROGMEM allows you to store read-only data (strings, lookup tables, fonts) in FLASH memory instead of SRAM, saving precious RAM.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
WHY THIS MATTERS:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
By default, all string literals and const arrays are copied from flash to SRAM at startup:
```c
const char msg[] = "Hello World";  // Stored in SRAM! (wastes 12 bytes)
```
With only 2KB SRAM on ATmega328P, this fills up fast.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
USING PROGMEM:
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
```c
#include <avr/io.h>
#include <avr/pgmspace.h>  // Required for PROGMEM and pgm_read_*

// Store in FLASH (not SRAM)
const char msg[] PROGMEM = "Hello from Flash!";
const uint8_t sine_table[] PROGMEM = {
    128, 152, 176, 198, 218, 234, 245, 252,
    255, 252, 245, 234, 218, 198, 176, 152,
    128, 104,  80,  58,  38,  22,  11,   4,
      0,   4,  11,  22,  38,  58,  80, 104
};

const uint16_t freqs[] PROGMEM = {262, 294, 330, 349, 392, 440, 494, 523};

void uart_print_P(const char *str_P) {
    char c;
    while ((c = pgm_read_byte(str_P++)) != 0) {
        // uart_putchar(c); — your UART transmit function
        while (!(UCSR0A & (1 << UDRE0)));
        UDR0 = c;
    }
}

int main(void) {
    UBRR0L = 103;
    UCSR0B = (1 << TXEN0);
    UCSR0C = (1 << UCSZ01) | (1 << UCSZ00);

    // ✅ Read string from FLASH
    uart_print_P(msg);
    uart_print_P(PSTR("\r\n"));  // PSTR() = inline PROGMEM string literal

    // ✅ Read 8-bit value from table
    uint8_t val = pgm_read_byte(&sine_table[5]);   // = 234

    // ✅ Read 16-bit value from table
    uint16_t freq = pgm_read_word(&freqs[0]);       // = 262

    // ✅ Read 32-bit value
    // uint32_t x = pgm_read_dword(&big_table[i]);

    // ✅ Copy PROGMEM block to SRAM
    uint8_t buf[8];
    memcpy_P(buf, sine_table, 8);  // Copies first 8 bytes to RAM

    while(1);
    return 0;
}
```

PROGMEM Reading Functions:
- pgm_read_byte(addr)   → uint8_t
- pgm_read_word(addr)   → uint16_t
- pgm_read_dword(addr)  → uint32_t
- pgm_read_float(addr)  → float
- memcpy_P(dst, src_P, n) → block copy from flash
- strcpy_P(dst, src_P)   → string copy from flash
- strcmp_P(str, str_P)   → compare RAM string with PROGMEM string
- strlen_P(str_P)        → string length in PROGMEM

