```c
#include <avr/io.h>
#include <avr/interrupt.h>

#define F_CPU      16000000UL
#define NUM_BUTTONS 4
#define DEBOUNCE_MS 20  // 20ms debounce window

// Timer0 gives 1ms ticks at 16MHz, prescaler /64, OCR0A=249
volatile uint16_t tick_ms = 0;

ISR(TIMER0_COMPA_vect) {
    tick_ms++;  // 1ms tick
}

void timer_init(void) {
    TCCR0A = (1 << WGM01);                      // CTC
    TCCR0B = (1 << CS01) | (1 << CS00);         // /64
    OCR0A  = 249;                                // 1ms
    TIMSK0 = (1 << OCIE0A);
}

// ─── Debounce Engine ─────────────────────────────────────
typedef enum {
    BTN_IDLE,
    BTN_PRESSED,
    BTN_HELD,
    BTN_RELEASED
} BtnState;

typedef struct {
    uint8_t   pin;            // Which PIND bit
    BtnState  state;
    uint16_t  press_time;     // Tick when button went LOW
    uint8_t   event_pressed;  // Flag: just pressed
    uint8_t   event_released; // Flag: just released
} Button;

Button buttons[NUM_BUTTONS];

void buttons_init(void) {
    for (uint8_t i = 0; i < NUM_BUTTONS; i++) {
        buttons[i].pin           = i;          // PD0–PD3
        buttons[i].state         = BTN_IDLE;
        buttons[i].event_pressed  = 0;
        buttons[i].event_released = 0;
        DDRD  &= ~(1 << i);   // Input
        PORTD |=  (1 << i);   // Pull-up
    }
}

void buttons_update(void) {
    uint16_t now = tick_ms;
    uint8_t pins = PIND;   // Sample all pins at once

    for (uint8_t i = 0; i < NUM_BUTTONS; i++) {
        uint8_t pressed = !(pins & (1 << buttons[i].pin));  // Active LOW

        switch (buttons[i].state) {
            case BTN_IDLE:
                if (pressed) {
                    buttons[i].state      = BTN_PRESSED;
                    buttons[i].press_time = now;
                }
                break;

            case BTN_PRESSED:
                if (!pressed) {
                    buttons[i].state = BTN_IDLE;  // Bounced, ignore
                } else if ((now - buttons[i].press_time) >= DEBOUNCE_MS) {
                    buttons[i].state         = BTN_HELD;
                    buttons[i].event_pressed = 1;  // Debounced press!
                }
                break;

            case BTN_HELD:
                if (!pressed) {
                    buttons[i].state = BTN_RELEASED;
                }
                break;

            case BTN_RELEASED:
                if (!pressed) {
                    buttons[i].state          = BTN_IDLE;
                    buttons[i].event_released = 1;  // Debounced release!
                } else {
                    buttons[i].state = BTN_HELD;   // Still held
                }
                break;
        }
    }
}

uint8_t button_pressed(uint8_t idx) {
    uint8_t e = buttons[idx].event_pressed;
    buttons[idx].event_pressed = 0;  // Clear after reading
    return e;
}

uint8_t button_released(uint8_t idx) {
    uint8_t e = buttons[idx].event_released;
    buttons[idx].event_released = 0;
    return e;
}

// ─── Main ─────────────────────────────────────────────────
int main(void) {
    DDRB |= 0x0F;           // PB0–PB3 as LED outputs
    PORTB &= ~0x0F;

    timer_init();
    buttons_init();
    sei();

    while (1) {
        buttons_update();

        for (uint8_t i = 0; i < NUM_BUTTONS; i++) {
            if (button_pressed(i)) {
                PORTB ^= (1 << i);  // Toggle corresponding LED
            }
        }
    }
    return 0;
}
```

State Machine for each button:
IDLE → (pin goes LOW) → PRESSED
PRESSED → (bounces high) → IDLE (ignored)
PRESSED → (stable for 20ms) → HELD + fire event_pressed
HELD → (pin goes HIGH) → RELEASED
RELEASED → (confirmed high) → IDLE + fire event_released
RELEASED → (pin goes LOW again) → HELD (still held)

The Input Capture Unit (ICU) is a hardware feature of Timer1 that automatically records the current timer value (ICR1) the instant a specified edge is detected on the ICP1 pin (PB0). This provides microsecond-accurate pulse measurements without software latency.

```c
#include <avr/io.h>
#include <avr/interrupt.h>

#define F_CPU 16000000UL

// At prescaler /8: 1 tick = 0.5µs
// Maximum measurable time = 65535 × 0.5µs = 32.77ms

volatile uint16_t rise_time = 0;
volatile uint16_t fall_time = 0;
volatile uint16_t pulse_width_ticks = 0;
volatile uint8_t  capture_done = 0;

typedef enum { WAIT_RISE, WAIT_FALL } CaptureState;
volatile CaptureState cap_state = WAIT_RISE;

ISR(TIMER1_CAPT_vect) {
    uint16_t captured = ICR1;  // Read captured timer value

    if (cap_state == WAIT_RISE) {
        rise_time = captured;
        // Switch to detect FALLING edge
        TCCR1B &= ~(1 << ICES1);  // ICES1=0 → falling edge
        TCNT1 = 0;                 // Reset timer to avoid overflow
        cap_state = WAIT_FALL;
    } else {
        fall_time = captured;
        pulse_width_ticks = fall_time;  // Since we reset at rise
        capture_done = 1;
        // Switch back to detect RISING edge
        TCCR1B |= (1 << ICES1);   // ICES1=1 → rising edge
        cap_state = WAIT_RISE;
    }
    // Clear Input Capture Flag (write 1 to clear)
    TIFR1 |= (1 << ICF1);
}

void icu_init(void) {
    DDRB  &= ~(1 << DDB0);    // ICP1 (PB0) as INPUT
    PORTB &= ~(1 << PORTB0);  // No pull-up (use external)

    // Timer1: Normal mode, prescaler /8
    TCCR1A = 0x00;
    TCCR1B = (1 << ICES1)    // Start with RISING edge capture
           | (1 << CS11);    // Prescaler /8 → 2MHz, 0.5µs/tick
    // Optional: Enable noise canceler (4-cycle filter)
    // TCCR1B |= (1 << ICNC1);

    TIMSK1 = (1 << ICIE1);   // Enable Input Capture Interrupt
    TCNT1  = 0;
}

// UART helpers
void uart_init(void) {
    UBRR0L = 103;
    UCSR0B = (1 << TXEN0);
    UCSR0C = (1 << UCSZ01) | (1 << UCSZ00);
}

void uart_print_uint16(uint16_t val) {
    char buf[6];
    uint8_t i = 5;
    buf[i--] = '\0';
    if (val == 0) buf[i--] = '0';
    while (val > 0 && i >= 0) {
        buf[i--] = '0' + (val % 10);
        val /= 10;
    }
    const char *p = &buf[i + 1];
    while (*p) {
        while (!(UCSR0A & (1 << UDRE0)));
        UDR0 = *p++;
    }
}

int main(void) {
    uart_init();
    icu_init();
    sei();

    while (1) {
        if (capture_done) {
            capture_done = 0;
            // Convert ticks to microseconds: ticks × 0.5µs
            uint32_t pulse_us = (uint32_t)pulse_width_ticks / 2;
            // Print result
            // uart_print_string("Pulse: ");
            uart_print_uint16((uint16_t)pulse_us);
            while (!(UCSR0A & (1 << UDRE0))); UDR0 = 'u';
            while (!(UCSR0A & (1 << UDRE0))); UDR0 = 's';
            while (!(UCSR0A & (1 << UDRE0))); UDR0 = '\r';
            while (!(UCSR0A & (1 << UDRE0))); UDR0 = '\n';
        }
    }
    return 0;
}
