bool uidMatch(byte* uid, int slot) {
  for (int i = 0; i < UID_SIZE; i++) {
    if (EEPROM.read(slot * UID_SIZE + i) != uid[i]) return false;
  }
  return true;
}

void storeUID(byte* uid, int slot) {
  for (int i = 0; i < UID_SIZE; i++) {
    EEPROM.write(slot * UID_SIZE + i, uid[i]);
  }
}

void setup() {
  Serial.begin(9600);
  SPI.begin();
  mfrc522.PCD_Init();
  lcd.init();
  lcd.backlight();
  lcd.print("Scan card...");
}

void loop() {
  if (!mfrc522.PICC_IsNewCardPresent() || !mfrc522.PICC_ReadCardSerial()) return;
  byte* uid = mfrc522.uid.uidByte;
  for (int slot = 0; slot < MAX_CARDS; slot++) {
    if (uidMatch(uid, slot)) {
      lcd.clear(); lcd.print("Known card!"); return;
    }
    if (EEPROM.read(slot * UID_SIZE) == 0xFF) {
      storeUID(uid, slot);
      lcd.clear(); lcd.print("Card saved!"); break;
    }
  }
  mfrc522.PICC_HaltA();
}

