#include <EEPROM.h>

// EEPROM addresses
#define EEPROM_FLAG_ADDR  0    // Address to store initialization flag
#define EEPROM_PASS_ADDR  1    // Starting address to store password characters
#define INIT_FLAG         0xAB // Arbitrary flag value to detect first boot
#define MAX_PASS_LEN      8

String correctPassword = "1234";  // Default password (used only on first boot)

void loadPassword() {
  // Check if EEPROM has been initialized
  if (EEPROM.read(EEPROM_FLAG_ADDR) == INIT_FLAG) {
    // Read saved password
    char buf[MAX_PASS_LEN + 1];
    for (int i = 0; i < MAX_PASS_LEN; i++) {
      buf[i] = EEPROM.read(EEPROM_PASS_ADDR + i);
      if (buf[i] == 0) break;
    }
    buf[MAX_PASS_LEN] = '\0';
    correctPassword = String(buf);
    Serial.print("Password loaded from EEPROM: ");
    Serial.println(correctPassword);
  } else {
    // First boot: save default password
    savePassword(correctPassword);
    Serial.println("First boot: default password saved to EEPROM.");
  }
}

void savePassword(String newPass) {
  EEPROM.write(EEPROM_FLAG_ADDR, INIT_FLAG);
  for (int i = 0; i < MAX_PASS_LEN; i++) {
    if (i < (int)newPass.length()) {
      EEPROM.write(EEPROM_PASS_ADDR + i, newPass[i]);
    } else {
      EEPROM.write(EEPROM_PASS_ADDR + i, 0);  // Null-terminate
    }
  }
  correctPassword = newPass;
}

// Call loadPassword() at the end of setup() to load from EEPROM on boot.

