  // Startup test: show 8 on each digit position for 1 second each
  for (int d = 0; d < 3; d++) {
    // Temporarily set all other digit pins HIGH (off for common anode)
    for (int i = 0; i < 3; i++) pinMode(digitPins[i], OUTPUT);
    for (int i = 0; i < 3; i++) digitalWrite(digitPins[i], HIGH);

    // Activate current digit (LOW = on for common anode)
    digitalWrite(digitPins[d], LOW);

    // Light all segments (LOW = on for common anode)
    for (int s = 6; s <= 13; s++) {
      pinMode(s, OUTPUT);
      digitalWrite(s, LOW);
    }
    delay(1000);
  }

  // Return control to SevSeg
  sevseg.setNumber(0);
}

