// PID constants — tune these for your robot
float Kp = 30.0;
float Ki = 0.0;
float Kd = 10.0;

float previousError = 0;
float integral = 0;
int baseSpeed = 150;
int maxSpeed = 255;

void applyMotorSpeed(int leftSpeed, int rightSpeed) {
  leftSpeed  = constrain(leftSpeed,  0, maxSpeed);
  rightSpeed = constrain(rightSpeed, 0, maxSpeed);
  motor1.run(FORWARD); motor1.setSpeed(leftSpeed);
  motor2.run(FORWARD); motor2.setSpeed(leftSpeed);
  motor3.run(FORWARD); motor3.setSpeed(rightSpeed);
  motor4.run(FORWARD); motor4.setSpeed(rightSpeed);
}

void setup() {
  pinMode(left, INPUT);
  pinMode(right, INPUT);
  Serial.begin(9600);
}

void loop() {
  int L = digitalRead(left);
  int R = digitalRead(right);

  // Error: -1 = too left, 0 = on track, 1 = too right
  float error = (float)(R - L);

  integral += error;
  float derivative = error - previousError;
  float correction = Kp * error + Ki * integral + Kd * derivative;
  previousError = error;

  int leftSpeed  = baseSpeed - (int)correction;
  int rightSpeed = baseSpeed + (int)correction;

  applyMotorSpeed(leftSpeed, rightSpeed);

  Serial.print("Error: "); Serial.print(error);
  Serial.print(" | Correction: "); Serial.println(correction);
  delay(10);
}

