enum RobotState { IDLE, FORWARD, TURN_LEFT, TURN_RIGHT, STOP_STATE };
RobotState currentState = IDLE;
RobotState lastState = IDLE;

void applyState(RobotState state) {
  switch (state) {
    case FORWARD:
      motor1.run(FORWARD); motor1.setSpeed(150);
      motor2.run(FORWARD); motor2.setSpeed(150);
      motor3.run(FORWARD); motor3.setSpeed(150);
      motor4.run(FORWARD); motor4.setSpeed(150);
      break;
    case TURN_RIGHT:
      motor1.run(FORWARD);  motor1.setSpeed(150);
      motor2.run(FORWARD);  motor2.setSpeed(150);
      motor3.run(BACKWARD); motor3.setSpeed(150);
      motor4.run(BACKWARD); motor4.setSpeed(150);
      break;
    case TURN_LEFT:
      motor1.run(BACKWARD); motor1.setSpeed(150);
      motor2.run(BACKWARD); motor2.setSpeed(150);
      motor3.run(FORWARD);  motor3.setSpeed(150);
      motor4.run(FORWARD);  motor4.setSpeed(150);
      break;
    case STOP_STATE:
    default:
      motor1.run(RELEASE); motor1.setSpeed(0);
      motor2.run(RELEASE); motor2.setSpeed(0);
      motor3.run(RELEASE); motor3.setSpeed(0);
      motor4.run(RELEASE); motor4.setSpeed(0);
      break;
  }
}

RobotState determineState(int L, int R) {
  if (L == 0 && R == 0) return FORWARD;
  if (L == 0 && R == 1) return TURN_RIGHT;
  if (L == 1 && R == 0) return TURN_LEFT;
  return STOP_STATE;
}

