  int L = digitalRead(LEFT_SENSOR);
  int R = digitalRead(RIGHT_SENSOR);

  currentState = determineState(L, R);

  if (currentState != lastState) {
    applyState(currentState);
    lastState = currentState;
    Serial.println(currentState);
  }
}

