const int LED_PINS[] = {2, 3, 4, 5};
const int BTN_PINS[] = {6, 7, 8, 9};
const int BUZZER = 10;
const int TONES[] = {262, 330, 392, 523}; // C4, E4, G4, C5
const int MAX_ROUNDS = 20;
int sequence[MAX_ROUNDS];
int round_num = 0;

void setup() {
  for (int i = 0; i < 4; i++) {
    pinMode(LED_PINS[i], OUTPUT);
    pinMode(BTN_PINS[i], INPUT_PULLUP);
  }
  pinMode(BUZZER, OUTPUT);
  randomSeed(analogRead(A0));
  Serial.begin(9600);
  startGame();
}

void startGame() {
  round_num = 0;
  Serial.println("Simon Says - Starting!");
  delay(1000);
  nextRound();
}

void nextRound() {
  sequence[round_num] = random(0, 4);
  round_num++;
  showSequence();
  getPlayerInput();
}

void showSequence() {
  for (int i = 0; i < round_num; i++) {
    int idx = sequence[i];
    digitalWrite(LED_PINS[idx], HIGH);
    tone(BUZZER, TONES[idx], 400);
    delay(500);
    digitalWrite(LED_PINS[idx], LOW);
    delay(200);
  }
}

void getPlayerInput() {
  for (int i = 0; i < round_num; i++) {
    bool pressed = false;
    while (!pressed) {
      for (int j = 0; j < 4; j++) {
        if (digitalRead(BTN_PINS[j]) == LOW) {
          delay(50);
          if (digitalRead(BTN_PINS[j]) == LOW) {
            if (j != sequence[i]) { gameOver(); return; }
            digitalWrite(LED_PINS[j], HIGH);
            tone(BUZZER, TONES[j], 200);
            delay(300);
            digitalWrite(LED_PINS[j], LOW);
            pressed = true;
            while(digitalRead(BTN_PINS[j]) == LOW);
          }
        }
      }
    }
  }
  if (round_num < MAX_ROUNDS) { delay(800); nextRound(); }
  else { Serial.println("YOU WIN!"); }
}

void gameOver() {
  Serial.print("Game Over! Score: "); Serial.println(round_num - 1);
  for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 4; j++) digitalWrite(LED_PINS[j], HIGH);
    tone(BUZZER, 100, 300); delay(300);
    for (int j = 0; j < 4; j++) digitalWrite(LED_PINS[j], LOW);
    delay(300);
  }
  delay(2000);
  startGame();
}

