#include <Wire.h>
#include <MPU6050.h>
MPU6050 mpu;
const int IN1=6, IN2=7, IN3=4, IN4=5, ENA=9, ENB=3;
double Kp=25, Ki=0.5, Kd=15;
double setpoint = 0.0; // Target angle (upright)
double input, output, errorSum=0, lastError=0;
unsigned long lastTime = 0;

void setup() {
  Wire.begin(); mpu.initialize();
  pinMode(IN1,OUTPUT); pinMode(IN2,OUTPUT);
  pinMode(IN3,OUTPUT); pinMode(IN4,OUTPUT);
}

double getAngle() {
  int16_t ax,ay,az,gx,gy,gz;
  mpu.getMotion6(&ax,&ay,&az,&gx,&gy,&gz);
  return atan2(ay, az) * 180.0 / PI;
}

void driveMotors(int spd) {
  spd = constrain(spd, -255, 255);
  if (spd > 0) {
    analogWrite(ENA, spd); analogWrite(ENB, spd);
    digitalWrite(IN1,HIGH); digitalWrite(IN2,LOW);
    digitalWrite(IN3,HIGH); digitalWrite(IN4,LOW);
  } else if (spd < 0) {
    analogWrite(ENA, -spd); analogWrite(ENB, -spd);
    digitalWrite(IN1,LOW); digitalWrite(IN2,HIGH);
    digitalWrite(IN3,LOW); digitalWrite(IN4,HIGH);
  } else {
    analogWrite(ENA, 0); analogWrite(ENB, 0);
  }
}

void loop() {
  unsigned long now = millis();
  double dt = (now - lastTime) / 1000.0;
  if (dt < 0.005) return;
  lastTime = now;
  input = getAngle();
  double error = setpoint - input;
  errorSum += error * dt;
  errorSum = constrain(errorSum, -50, 50); // Anti-windup
  double dError = (error - lastError) / dt;
  output = Kp*error + Ki*errorSum + Kd*dError;
  lastError = error;
  driveMotors((int)output);
}

