    bool match = true;
    for (int b = 0; b < 4; b++) {
      if (rfid.uid.uidByte[b] != KNOWN_UIDS[u][b]) { match = false; break; }
    }
    if (match) {
      Serial.print(NAMES[u]); Serial.print(",");
      for (int b = 0; b < rfid.uid.size; b++) { Serial.print(rfid.uid.uidByte[b], HEX); }
      Serial.print(",");
      Serial.print(now.year()); Serial.print("/"); Serial.print(now.month()); Serial.print("/"); Serial.print(now.day());
      Serial.print(",");
      Serial.print(now.hour()); Serial.print(":"); Serial.print(now.minute()); Serial.print(":"); Serial.println(now.second());
      break;
    }
  }
  rfid.PICC_HaltA();
