const int SAMPLE_RATE = 1000; // Samples per second
int samples[SAMPLES];

void setup() {
  pinMode(LED_PIN, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  // Collect samples
  for (int i = 0; i < SAMPLES; i++) {
    samples[i] = analogRead(MIC_PIN);
    delayMicroseconds(1000000 / SAMPLE_RATE);
  }
  // Find zero crossings to estimate frequency
  int baseline = 512; // Midpoint of ADC
  int crossings = 0;
  bool prevHigh = samples[0] > baseline;
  for (int i = 1; i < SAMPLES; i++) {
    bool currHigh = samples[i] > baseline;
    if (currHigh != prevHigh) crossings++;
    prevHigh = currHigh;
  }
  float duration = (float)SAMPLES / SAMPLE_RATE;
  float frequency = (crossings / 2.0) / duration;
  Serial.print("Frequency: "); Serial.print(frequency); Serial.println(" Hz");
  if (frequency > 200 && frequency < 400) digitalWrite(LED_PIN, HIGH);
  else digitalWrite(LED_PIN, LOW);
}

