  int freq = map(potVal, 0, 1023, MIN_FREQ, MAX_FREQ);
  long period = 1000000L / freq; // Period in microseconds
  long highTime = period / 2;
  long lowTime = period - highTime;
  // Manual PWM (for frequencies Arduino's analogWrite can't achieve)
  digitalWrite(PWM_PIN, HIGH);
  delayMicroseconds(highTime);
  digitalWrite(PWM_PIN, LOW);
  delayMicroseconds(lowTime);
  // Print every 100ms
  static unsigned long lastPrint = 0;
  if (millis() - lastPrint > 100) {
    Serial.print("Frequency: "); Serial.print(freq); Serial.println(" Hz");
    lastPrint = millis();
  }
}

