}

const int CHARGE_PIN = 7;
const int MEASURE_PIN = A0;
const float R = 10000.0; // 10kΩ resistor
const float VCC = 5.0;

void setup() {
  pinMode(CHARGE_PIN, OUTPUT);
  pinMode(MEASURE_PIN, INPUT);
  Serial.begin(9600);
  Serial.println("Time(ms),Voltage(V)");
}

void measureChargeCurve() {
  // Discharge first
  pinMode(CHARGE_PIN, OUTPUT);
  digitalWrite(CHARGE_PIN, LOW);
  delay(5000);
  // Start charging and measure
  unsigned long startTime = millis();
  digitalWrite(CHARGE_PIN, HIGH);
  float voltage = 0;
  while (voltage < 4.5) {
    int raw = analogRead(MEASURE_PIN);
    voltage = raw * VCC / 1023.0;
    unsigned long elapsed = millis() - startTime;
    Serial.print(elapsed); Serial.print(","); Serial.println(voltage);
    // Estimate capacitance: t63 = R*C at 63.2% of VCC (3.16V)
    if (voltage >= 3.16 && voltage < 3.20) {
      float tau = elapsed / 1000.0;
      float C = tau / R;
      Serial.print("# Capacitance: "); Serial.print(C * 1e6); Serial.println(" µF");
    }
  }
  digitalWrite(CHARGE_PIN, LOW);
}

void loop() {
  measureChargeCurve();
  delay(10000);
}

