// pH sensor calibration constants (adjust with known pH buffers)
const float OFFSET = 0.0;
const float TEMP_COEFF = 0.03; // pH/°C compensation

void setup() {
  Serial.begin(9600);
  dht.begin();
  Serial.println("pH Meter with Temp Compensation");
}

float readPH(float temperature) {
  int raw = 0;
  for (int i = 0; i < 32; i++) { raw += analogRead(PH_PIN); delay(20); }
  raw /= 32;
  float voltage = raw * 5.0 / 1023.0;
  float ph = 7.0 + ((2.5 - voltage) / 0.18) + OFFSET;
  // Temperature compensation
  ph = ph - TEMP_COEFF * (temperature - 25.0);
  return ph;
}

void loop() {
  float temp = dht.readTemperature();
  if (isnan(temp)) temp = 25.0; // Default if sensor fails
  float ph = readPH(temp);
  Serial.print("Temp: "); Serial.print(temp); Serial.print(" C | pH: "); Serial.println(ph, 2);
  if (ph < 6.0) Serial.println("Soil is ACIDIC");
  else if (ph > 7.5) Serial.println("Soil is ALKALINE");
  else Serial.println("Soil is NEUTRAL");
  delay(5000);
}

