const int LDR_PIN = A0;
const int HEADLIGHT_PIN = 9; // PWM
const int MIN_BRIGHTNESS = 30;
const int MAX_BRIGHTNESS = 255;
const int DARK_THRESHOLD = 300;
const int BRIGHT_THRESHOLD = 700;
int smoothedLDR = 512;

void setup() {
  pinMode(HEADLIGHT_PIN, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  int ldrRaw = analogRead(LDR_PIN);
  // Exponential smoothing to avoid flickering
  smoothedLDR = (smoothedLDR * 9 + ldrRaw) / 10;
  int brightness;
  if (smoothedLDR < DARK_THRESHOLD) {
    brightness = MAX_BRIGHTNESS; // Very dark: full brightness
  } else if (smoothedLDR > BRIGHT_THRESHOLD) {
    brightness = MIN_BRIGHTNESS; // Very bright: minimum light
  } else {
    // Map inversely
    brightness = map(smoothedLDR, DARK_THRESHOLD, BRIGHT_THRESHOLD, MAX_BRIGHTNESS, MIN_BRIGHTNESS);
  }
  analogWrite(HEADLIGHT_PIN, brightness);
  Serial.print("LDR: "); Serial.print(smoothedLDR);
  Serial.print(" | Light: "); Serial.println(brightness);
  delay(100);
}

