#include <SoftwareSerial.h>
SoftwareSerial gps(4, 3);
String nmeaSentence;

void setup() {
  Serial.begin(9600);
  gps.begin(9600);
}

void parseGGA(String sentence) {
  if (!sentence.startsWith("$GPGGA")) return;
  int idx = 0;
  String fields[15];
  for (int i = 0; i < 15; i++) {
    int comma = sentence.indexOf(',', idx);
    if (comma == -1) { fields[i] = sentence.substring(idx); break; }
    fields[i] = sentence.substring(idx, comma);
    idx = comma + 1;
  }
  if (fields[6] == "0") { Serial.println("No GPS fix"); return; }
  Serial.print("Lat: "); Serial.print(fields[2]); Serial.print(" "); Serial.println(fields[3]);
  Serial.print("Lng: "); Serial.print(fields[4]); Serial.print(" "); Serial.println(fields[5]);
  Serial.print("Alt: "); Serial.print(fields[9]); Serial.println(" m");
  Serial.print("Satellites: "); Serial.println(fields[7]);
}

void loop() {
  if (gps.available()) {
    char c = gps.read();
    if (c == '\n') {
      parseGGA(nmeaSentence);
      nmeaSentence = "";
    } else {
      nmeaSentence += c;
    }
  }
}

const int SOUND_PIN = A0;
const int RELAY_PIN = 7;
const int THRESHOLD = 600;
const long CLAP_WINDOW = 400; // ms window for double clap
const long MIN_CLAP_GAP = 50;  // ignore noise faster than this
bool relayState = false;
unsigned long lastClapTime = 0;
int clapCount = 0;

void setup() {
  pinMode(RELAY_PIN, OUTPUT);
  digitalWrite(RELAY_PIN, LOW);
  Serial.begin(9600);
}

void loop() {
  int soundLevel = analogRead(SOUND_PIN);
  if (soundLevel > THRESHOLD) {
    unsigned long now = millis();
    if (now - lastClapTime > MIN_CLAP_GAP) {
      clapCount++;
      Serial.print("Clap #"); Serial.println(clapCount);
      lastClapTime = now;
    }
  }
  if (clapCount >= 2) {
    relayState = !relayState;
    digitalWrite(RELAY_PIN, relayState);
    Serial.print("Relay: "); Serial.println(relayState ? "ON" : "OFF");
    clapCount = 0;
  }
  if (millis() - lastClapTime > CLAP_WINDOW) {
    clapCount = 0; // Reset if window expired
  }
}

