#include <Wire.h>
#include <HMC5883L.h>
HMC5883L compass;
float minX, maxX, minY, maxY;
bool calibrated = false;
const int CALIBRATE_SECS = 15;

void setup() {
  Wire.begin();
  Serial.begin(9600);
  compass.initialize();
  compass.setRange(HMC5883L_RANGE_1_3GA);
  Serial.println("Rotate compass 360° for calibration...");
  unsigned long start = millis();
  minX = minY = 9999; maxX = maxY = -9999;
  while (millis() - start < CALIBRATE_SECS * 1000UL) {
    int16_t x, y, z;
    compass.getHeading(&x, &y, &z);
    if (x < minX) minX = x; if (x > maxX) maxX = x;
    if (y < minY) minY = y; if (y > maxY) maxY = y;
    delay(100);
  }
  Serial.println("Calibration done.");
}

void loop() {
  int16_t x, y, z;
  compass.getHeading(&x, &y, &z);
  float normX = (x - (minX + maxX) / 2.0);
  float normY = (y - (minY + maxY) / 2.0);
  float heading = atan2(normY, normX) * 180.0 / PI;
  if (heading < 0) heading += 360;
  Serial.print("Heading: "); Serial.print(heading, 1); Serial.println("°");
  delay(200);
}

