const int VOLT_PIN = A0;
const int LED_LOW  = 8;
const int LED_OK   = 9;
const int BUZZER   = 7;
// Voltage divider: R1=10kΩ, R2=10kΩ (max 10V input)
const float R1 = 10000.0, R2 = 10000.0, VREF = 5.0;
const float LOW_VOLT = 3.5;  // Low battery threshold
const float GOOD_VOLT = 3.9; // Hysteresis threshold
bool lowBattery = false;

void setup() {
  pinMode(LED_LOW, OUTPUT);
  pinMode(LED_OK, OUTPUT);
  pinMode(BUZZER, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  int raw = analogRead(VOLT_PIN);
  float vOut = (raw / 1023.0) * VREF;
  float vBatt = vOut * (R1 + R2) / R2;
  Serial.print("Battery: "); Serial.print(vBatt); Serial.println(" V");
  if (!lowBattery && vBatt < LOW_VOLT) {
    lowBattery = true;
    Serial.println("LOW BATTERY WARNING!");
  } else if (lowBattery && vBatt > GOOD_VOLT) {
    lowBattery = false;
  }
  if (lowBattery) {
    digitalWrite(LED_LOW, HIGH); digitalWrite(LED_OK, LOW);
    tone(BUZZER, 500, 200);
  } else {
    digitalWrite(LED_LOW, LOW); digitalWrite(LED_OK, HIGH);
    noTone(BUZZER);
  }
  delay(2000);
}

