// Trained weights for a 2-2-1 neural network (XOR)
// Layer 1 weights and biases
float w1[2][2] = {{5.0, -5.0}, {5.0, -5.0}};
float b1[2] = {-2.0, 7.5};
// Layer 2 weights and bias
float w2[2] = {10.0, 10.0};
float b2 = -5.0;

float sigmoid(float x) { return 1.0 / (1.0 + exp(-x)); }

float xor_predict(float a, float b) {
  // Hidden layer
  float h1 = sigmoid(w1[0][0]*a + w1[1][0]*b + b1[0]);
  float h2 = sigmoid(w1[0][1]*a + w1[1][1]*b + b1[1]);
  // Output layer
  return sigmoid(w2[0]*h1 + w2[1]*h2 + b2);
}

