// Simple 1D Kalman filter for accelerometer angle
struct KalmanFilter {
  float Q_angle = 0.001; // Process noise
  float Q_bias  = 0.003; // Gyroscope bias noise
  float R_measure = 0.03; // Measurement noise
  float angle = 0, bias = 0;
  float P[2][2] = {{0,0},{0,0}};
  float getAngle(float newAngle, float newRate, float dt) {
    float rate = newRate - bias;
    angle += dt * rate;
    P[0][0] += dt * (dt*P[1][1] - P[0][1] - P[1][0] + Q_angle);
    P[0][1] -= dt * P[1][1]; P[1][0] -= dt * P[1][1]; P[1][1] += Q_bias * dt;
    float S = P[0][0] + R_measure;
    float K[2] = {P[0][0]/S, P[1][0]/S};
    float y = newAngle - angle;
    angle += K[0] * y; bias += K[1] * y;
    P[0][0] -= K[0]*P[0][0]; P[0][1] -= K[0]*P[0][1];
    P[1][0] -= K[1]*P[0][0]; P[1][1] -= K[1]*P[0][1];
    return angle;
  }
};

