const int ENC_A = 2; // Interrupt pin
const int ENC_B = 3; // Interrupt pin
volatile long encoderCount = 0;
volatile int lastEncoded = 0;
unsigned long lastPrint = 0;
long lastCount = 0;

void encoderISR() {
  int MSB = digitalRead(ENC_A);
  int LSB = digitalRead(ENC_B);
  int encoded = (MSB << 1) | LSB;
  int sum = (lastEncoded << 2) | encoded;
  if (sum == 0b1101 || sum == 0b0100 || sum == 0b0010 || sum == 0b1011) encoderCount++;
  if (sum == 0b1110 || sum == 0b0111 || sum == 0b0001 || sum == 0b1000) encoderCount--;
  lastEncoded = encoded;
}

void setup() {
  pinMode(ENC_A, INPUT_PULLUP);
  pinMode(ENC_B, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_A), encoderISR, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC_B), encoderISR, CHANGE);
  Serial.begin(9600);
}

void loop() {
  if (millis() - lastPrint >= 500) {
    noInterrupts();
    long count = encoderCount;
    interrupts();
    long delta = count - lastCount;
    lastCount = count;
    float rpm = (delta / 12.0 / 0.5) * 60.0; // 12 counts/rev, 0.5s sample
    Serial.print("Position: "); Serial.print(count);
    Serial.print(" | RPM: "); Serial.println(rpm, 0);
    lastPrint = millis();
  }
}

