void manageStorage() {
  uint64_t total = SD_MMC.totalBytes();
  uint64_t used  = SD_MMC.usedBytes();
  if ((float)used / total > 0.90) {
    File root = SD_MMC.open("/");
    File oldest;
    time_t oldestTime = LONG_MAX;
    File f = root.openNextFile();
    while (f) {
      if (!f.isDirectory() && f.getLastWrite() < oldestTime) {
        oldestTime = f.getLastWrite();
        oldest = f;
      }
      f = root.openNextFile();
    }
    if (oldest) {
      String path = "/" + String(oldest.name());
      oldest.close();
      SD_MMC.remove(path);
      Serial.println("Deleted old file: " + path);
    }
  }
}

