HTTP POST can send data in several formats, determined by the `Content-Type` header.

**Raw binary POST (used in the uploaded project):**
```cpp
client.addHeader("Content-Type", "image/jpeg");
client.POST(fb->buf, fb->len);
```
The request body is exactly the raw bytes of the JPEG image. No encoding, no boundary markers. The server receives the binary blob directly in `request.body` or as a stream. This is efficient for image/file upload APIs that expect binary input.

**Multipart form-data POST:**
```cpp
client.addHeader("Content-Type", "multipart/form-data; boundary=----Boundary");
// Body includes boundary markers, field names, and base64 or raw data
```
Used when uploading files via HTML forms or when the API expects files alongside text fields. More overhead due to boundary encoding.

**Application/x-www-form-urlencoded:**
```cpp
client.addHeader("Content-Type", "application/x-www-form-urlencoded");
client.POST("key1=value1&key2=value2");
```
For simple key-value text data. Cannot efficiently encode binary.

**JSON POST:**
```cpp
client.addHeader("Content-Type", "application/json");
client.POST("{\"sensor\":\"temp\",\"value\":25.5}");
```
Best for structured data to REST APIs.

**Recommendation:** Use raw binary (`image/jpeg`) for direct camera uploads to a custom server endpoint. Use JSON for sensor data. Use form-data when integrating with third-party services that require it (e.g., some cloud vision APIs).

#include <Arduino.h>

#define LED_PIN 2

void blinkTask(void* parameter) {
  pinMode(LED_PIN, OUTPUT);
  while (true) {
    digitalWrite(LED_PIN, HIGH);
    vTaskDelay(500 / portTICK_PERIOD_MS);
    digitalWrite(LED_PIN, LOW);
    vTaskDelay(500 / portTICK_PERIOD_MS);
  }
}

void printTask(void* parameter) {
  while (true) {
    Serial.printf("Hello from Core %d at %lu ms\n",
      xPortGetCoreID(), millis());
    vTaskDelay(2000 / portTICK_PERIOD_MS);
  }
}

void setup() {
  Serial.begin(115200);

  // Create task on Core 0
  xTaskCreatePinnedToCore(
    blinkTask,    // function
    "BlinkTask",  // name
    1024,         // stack size (bytes)
    NULL,         // parameter
    1,            // priority (1 = low)
    NULL,         // task handle
    0             // core ID
  );

  // Create task on Core 1
  xTaskCreatePinnedToCore(
    printTask,
    "PrintTask",
    2048,
    NULL,
    1,
    NULL,
    1
  );
}

void loop() {
  // Main loop is itself a FreeRTOS task on Core 1
  // Keep it alive or delete it
  vTaskDelay(1000 / portTICK_PERIOD_MS);
}

