The Preferences library wraps the ESP32's NVS (Non-Volatile Storage) with a simple Arduino-friendly API. Using it to save and restore WiFi credentials allows the device to connect on startup without hard-coding credentials.

Saving credentials (e.g., from a config portal or serial input):
```cpp
#include <Preferences.h>
Preferences prefs;

void saveCredentials(const char* ssid, const char* password) {
  prefs.begin("wifi", false);
  prefs.putString("ssid", ssid);
  prefs.putString("pass", password);
  prefs.end();
}
```

Loading credentials at boot:
```cpp
#include <WiFi.h>
#include <Preferences.h>
Preferences prefs;

void setup() {
  Serial.begin(115200);
  prefs.begin("wifi", true);  // true = read-only
  String ssid = prefs.getString("ssid", "");
  String pass = prefs.getString("pass", "");
  prefs.end();

  if (ssid.length() > 0) {
    WiFi.begin(ssid.c_str(), pass.c_str());
    Serial.println("Connecting to " + ssid);
  } else {
