  HTTPClient http;
  WiFiClient client;
  http.begin(client, "http://api.example.com/data");  // preferred form
  http.addHeader("Content-Type", "application/json");
  int code = http.POST(json);
  if (code < 0) Serial.printf("HTTP error: %s\n", http.errorToString(code).c_str());
  http.end();  // <-- CRITICAL: always call end()

  Serial.printf("Free heap: %d\n", ESP.getFreeHeap());  // monitor heap
  delay(5000);
}
```

