To make an ESP32 respond to MQTT messages (subscribe mode), you need a callback function that the PubSubClient library calls whenever a message arrives on a subscribed topic.

```cpp
#include <WiFi.h>
#include <PubSubClient.h>

#define LED_PIN 2
const char* ssid       = "YOUR_SSID";
const char* password   = "YOUR_PASS";
const char* mqttServer = "broker.hivemq.com";
const char* subTopic   = "esp32/led";

WiFiClient espClient;
PubSubClient client(espClient);

void messageCallback(char* topic, byte* payload, unsigned int length) {
  String msg = "";
  for (int i = 0; i < length; i++) msg += (char)payload[i];
  Serial.println("Message on " + String(topic) + ": " + msg);
  if (msg == "ON")  digitalWrite(LED_PIN, HIGH);
  if (msg == "OFF") digitalWrite(LED_PIN, LOW);
}

void reconnect() {
  while (!client.connected()) {
    if (client.connect("ESP32Sub")) {
      client.subscribe(subTopic);  // subscribe after every reconnect
    } else {
      delay(2000);
    }
  }
}

void setup() {
  Serial.begin(115200);
  pinMode(LED_PIN, OUTPUT);
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  client.setServer(mqttServer, 1883);
  client.setCallback(messageCallback);
}

void loop() {
  if (!client.connected()) reconnect();
  client.loop();
}
```

Key points: `client.setCallback()` registers the handler, `client.subscribe()` must be called after every (re)connection, and `client.loop()` must run every iteration to process incoming messages.

