When two FreeRTOS tasks access the same variable concurrently, a race condition can corrupt the data. A mutex (mutual exclusion semaphore) ensures only one task accesses the shared resource at a time.

```cpp
#include <freertos/semphr.h>

SemaphoreHandle_t xMutex;
float sharedTemp = 0.0f;

void sensorTask(void* param) {
  for (;;) {
    float t = readSensor();  // blocking sensor read
    if (xSemaphoreTake(xMutex, portMAX_DELAY) == pdTRUE) {
      sharedTemp = t;  // safe write inside mutex
      xSemaphoreGive(xMutex);
    }
    vTaskDelay(2000 / portTICK_PERIOD_MS);
  }
}

void displayTask(void* param) {
  for (;;) {
    float t;
    if (xSemaphoreTake(xMutex, portMAX_DELAY) == pdTRUE) {
      t = sharedTemp;  // safe read inside mutex
      xSemaphoreGive(xMutex);
    }
    Serial.printf("Temp: %.2f\n", t);
    vTaskDelay(1000 / portTICK_PERIOD_MS);
  }
}

void setup() {
  Serial.begin(115200);
  xMutex = xSemaphoreCreateMutex();
  xTaskCreatePinnedToCore(sensorTask, "Sensor", 4096, NULL, 1, NULL, 0);
  xTaskCreatePinnedToCore(displayTask, "Display", 4096, NULL, 1, NULL, 1);
}
```

`xSemaphoreTake()` acquires the mutex; `xSemaphoreGive()` releases it. Always release the mutex — forgetting to call `Give` causes a deadlock.

