static int queueDrawMCU(JPEGDRAW *pDraw) {
  // Calculate pixel data size for this MCU block
  int len = pDraw->iWidth * pDraw->iHeight * 2; // 2 bytes per RGB565 pixel

  // Get next slot in the ring buffer
  JPEGDRAW *j = &jpegdraws[_draw_queue_cnt % NUMBER_OF_DRAW_BUFFER];

  // Copy draw parameters
  j->x = pDraw->x;
  j->y = pDraw->y;
  j->iWidth = pDraw->iWidth;
  j->iHeight = pDraw->iHeight;

  // Copy pixel data into pre-allocated DMA buffer
  memcpy(j->pPixels, pDraw->pPixels, len);

  // Advance ring buffer counter
  ++_draw_queue_cnt;

  // Send pointer to draw task (blocks if queue is full)
  xQueueSend(_xqh, &j, portMAX_DELAY);

  return 1; // return 1 to continue decoding
}

