static void decode_task(void *arg) {
  paramDecodeTask *p = (paramDecodeTask *)arg;
  mjpegBuf *mBuf;
  log_i("decode_task started on core %d", xPortGetCoreID());

  while (xQueueReceive(p->xqh, &mBuf, portMAX_DELAY)) {
    unsigned long s = millis();

    // Open JPEG from RAM buffer
    _jpegDec.openRAM(mBuf->buf, mBuf->size, p->drawFunc);

    // Configure output pixel format
    if (_useBigEndian) {
      _jpegDec.setPixelType(RGB565_BIG_ENDIAN);
    }

    // Limit MCU output size to prevent overflow
    _jpegDec.setMaxOutputSize(MAXOUTPUTSIZE);

    // Decode the full frame (x=0, y=0, options=0)
    _jpegDec.decode(0, 0, 0);
    _jpegDec.close();

    total_decode_video_ms += millis() - s;
  }

  // Queue was deleted, clean up
  log_i("decode_task ending");
  vTaskDelete(NULL);
}

