static void draw_task(void *arg) {
  paramDrawTask *p = (paramDrawTask *)arg;
  JPEGDRAW *pDraw;
  log_i("draw_task started on core %d", xPortGetCoreID());

  // Block waiting for draw commands from decode task
  while (xQueueReceive(p->xqh, &pDraw, portMAX_DELAY)) {
    // Call the registered draw function (e.g., drawMCU)
    // which calls gfx->draw16bitRGBBitmap() via SPI DMA
    p->drawFunc(pDraw);
