There are two bugs in this code:

1. **Serial baud rate too low**: ESP32 boot messages are at 115200. Change `Serial.begin(9600)` to `Serial.begin(115200)` to see output correctly.

2. **Infinite blocking loop with no feedback or timeout**: The `while (WiFi.status() != WL_CONNECTED) {}` loop will freeze forever if credentials are wrong or the network is out of range.

Fixed code:
```cpp
#include <WiFi.h>
void setup() {
  Serial.begin(115200);
  WiFi.begin("MySSID", "MyPass");
  int attempts = 0;
  while (WiFi.status() != WL_CONNECTED && attempts < 20) {
    delay(500);
    Serial.print(".");
    attempts++;
  }
  if (WiFi.status() == WL_CONNECTED) {
    Serial.println("\nConnected! IP: " + WiFi.localIP().toString());
  } else {
    Serial.println("\nFailed to connect. Check SSID/password.");
  }
}
void loop() {}
```

