output:
This code has several problems causing MQTT disconnections:

1. **No client.loop() call**: MQTT requires `client.loop()` every iteration to maintain the connection and handle keep-alive packets. Without it, the broker closes the connection after the keep-alive timeout.
2. **No reconnection logic**: If the connection drops, the code never tries to reconnect.
3. **No WiFi wait**: `WiFi.begin()` is async; publishing before WiFi connects will silently fail.
4. **Duplicate client ID**: Using a static `"ESP32"` ID causes conflicts when multiple devices connect.

Fixed code:
```cpp
#include <WiFi.h>
#include <PubSubClient.h>
WiFiClient espClient;
PubSubClient client(espClient);

void reconnect() {
  while (!client.connected()) {
    String clientId = "ESP32-" + String(random(0xffff), HEX);
    if (client.connect(clientId.c_str())) {
      Serial.println("MQTT connected");
    } else {
      delay(5000);
    }
  }
}

void setup() {
  Serial.begin(115200);
  WiFi.begin("ssid", "pass");
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  client.setServer("broker.hivemq.com", 1883);
}

void loop() {
  if (!client.connected()) reconnect();
  client.loop(); // CRITICAL: must call every loop
  static unsigned long last = 0;
  if (millis() - last > 1000) {
    last = millis();
    client.publish("test", "hello");
  }
}
```

