#include <esp_sleep.h>
void setup() {
  Serial.begin(115200);
  WiFi.disconnect(true);
  WiFi.mode(WIFI_OFF);
  btStop();
  delay(100);
  Serial.println("Going to sleep for 10s");
  Serial.flush();
  esp_sleep_enable_timer_wakeup(10000000ULL); // 10s in microseconds
  esp_deep_sleep_start();
}
void loop() {}
```

