  analogSetAttenuation(ADC_11db);
}
void loop() {
  int raw = analogRead(34); // GPIO 34 = ADC1_CH6, safe with WiFi
  float voltage = raw * (3.3 / 4095.0);
  Serial.print("Raw: "); Serial.print(raw);
  Serial.print(" | Voltage: "); Serial.println(voltage, 3);
  delay(100);
}
```

