    Serial.println("Bluetooth init failed!");
    return;
  }
  Serial.println("Bluetooth started. Pair with 'ESP32-BT-Device'");
}

void loop() {
  // Relay USB Serial <-> Bluetooth Serial
  if (SerialBT.available()) {
    String received = "";
    while (SerialBT.available()) {
      received += (char)SerialBT.read();
    }
    Serial.print("BT received: "); Serial.println(received);
    SerialBT.println("Echo: " + received);
  }

  if (Serial.available()) {
    String msg = Serial.readStringUntil('\n');
    SerialBT.println(msg);
  }

  delay(20);
}
