FreeRTOS Queues provide thread-safe communication between tasks. A producer task writes to the queue, and a consumer task reads from it — without needing mutexes for this pattern.

**Example: Sensor task produces readings, display task consumes them:**
```cpp
#include <freertos/FreeRTOS.h>
#include <freertos/queue.h>

QueueHandle_t sensorQueue;

typedef struct {
  float temperature;
  float humidity;
  unsigned long timestamp;
} SensorData;

void sensorTask(void *param) {
  SensorData data;
  for (;;) {
    // Simulate sensor reading
    data.temperature = 20.0 + (random(0, 100) / 10.0);
    data.humidity = 50.0 + (random(0, 200) / 10.0);
    data.timestamp = millis();

    // Send to queue (wait max 100ms if queue full)
    if (xQueueSend(sensorQueue, &data, pdMS_TO_TICKS(100)) != pdTRUE) {
      Serial.println("Queue full! Data dropped.");
    }
    vTaskDelay(pdMS_TO_TICKS(2000)); // read every 2 seconds
  }
}

void displayTask(void *param) {
  SensorData received;
  for (;;) {
    // Block until data available (portMAX_DELAY = wait forever)
    if (xQueueReceive(sensorQueue, &received, portMAX_DELAY) == pdTRUE) {
      Serial.printf("[%lu ms] Temp: %.1f°C | Hum: %.1f%%\n",
        received.timestamp, received.temperature, received.humidity);
    }
  }
}

void setup() {
  Serial.begin(115200);
  // Create queue: 10 items, each sizeof(SensorData)
  sensorQueue = xQueueCreate(10, sizeof(SensorData));
  if (sensorQueue == NULL) {
    Serial.println("Queue creation failed!");
    return;
  }
  xTaskCreate(sensorTask, "Sensor", 2048, NULL, 1, NULL);
  xTaskCreate(displayTask, "Display", 2048, NULL, 1, NULL);
}
void loop() { vTaskDelay(pdMS_TO_TICKS(1000)); }
```

