ESP32's I2S (Inter-IC Sound) peripheral is a serial audio bus for transmitting digital audio. It has two I2S controllers (I2S0, I2S1) and can handle sample rates from 8kHz to 96kHz.

**I2S modes:**
- **Standard I2S**: For external DAC/ADC chips (PCM5102, MAX98357)
- **PDM mode**: For MEMS microphones (INMP441, SPH0645)
- **ADC/DAC built-in mode**: Uses internal ESP32 ADC/DAC (lower quality)

**I2S Audio Output (MAX98357 amplifier):**
```cpp
#include <driver/i2s.h>

#define I2S_WS  25  // Word Select / LRCLK
#define I2S_SD  22  // Serial Data / DIN
#define I2S_SCK 26  // Bit Clock / BCLK

void i2sInit() {
  i2s_config_t cfg = {
    .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX),
    .sample_rate = 44100,
    .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
    .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
    .communication_format = I2S_COMM_FORMAT_STAND_I2S,
    .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
    .dma_buf_count = 8,
    .dma_buf_len = 1024,
    .use_apll = false
  };
  i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);

  i2s_pin_config_t pins = {
    .bck_io_num = I2S_SCK,
    .ws_io_num = I2S_WS,
    .data_out_num = I2S_SD,
    .data_in_num = I2S_PIN_NO_CHANGE
  };
  i2s_set_pin(I2S_NUM_0, &pins);
}

void playTone(int freq, int duration_ms) {
  int sampleRate = 44100;
  int samplesPerCycle = sampleRate / freq;
  int totalSamples = (sampleRate * duration_ms) / 1000;
  int16_t buffer[512];
  int bufIdx = 0;
  size_t written;
  for (int s = 0; s < totalSamples; s++) {
    float angle = 2.0 * PI * (s % samplesPerCycle) / samplesPerCycle;
    buffer[bufIdx++] = (int16_t)(10000 * sin(angle)); // amplitude 10000
    if (bufIdx >= 512) {
      i2s_write(I2S_NUM_0, buffer, sizeof(buffer), &written, portMAX_DELAY);
      bufIdx = 0;
    }
  }
}

