#include <HardwareSerial.h>

#define RS485_RX 16
#define RS485_TX 17
#define RS485_DE 4   // Driver Enable / Receiver Enable
#define SLAVE_ID 1
#define BAUD_RATE 9600

HardwareSerial rs485(2);

uint16_t crc16(uint8_t *buf, int len) {
  uint16_t crc = 0xFFFF;
  for (int i = 0; i < len; i++) {
    crc ^= buf[i];
    for (int b = 0; b < 8; b++) {
      if (crc & 1) crc = (crc >> 1) ^ 0xA001;
      else crc >>= 1;
    }
  }
  return crc;
}

int16_t readHoldingRegister(uint8_t slaveId, uint16_t regAddr) {
  uint8_t request[8];
  request[0] = slaveId;
  request[1] = 0x03;          // Function code: Read Holding Registers
  request[2] = (regAddr >> 8) & 0xFF;
  request[3] = regAddr & 0xFF;
  request[4] = 0x00;           // Number of registers Hi
  request[5] = 0x01;           // Number of registers Lo
  uint16_t crc = crc16(request, 6);
  request[6] = crc & 0xFF;
  request[7] = (crc >> 8) & 0xFF;

  digitalWrite(RS485_DE, HIGH); // Enable transmit
  rs485.write(request, 8);
  rs485.flush();
  digitalWrite(RS485_DE, LOW);  // Enable receive

  unsigned long timeout = millis() + 1000;
  uint8_t response[7];
  int idx = 0;
  while (millis() < timeout && idx < 7) {
    if (rs485.available()) response[idx++] = rs485.read();
  }

  if (idx < 7) { Serial.println("Timeout"); return -1; }

  uint16_t rxCRC = response[5] | (response[6] << 8);
  if (crc16(response, 5) != rxCRC) { Serial.println("CRC Error"); return -1; }

  return (int16_t)((response[3] << 8) | response[4]);
}

void setup() {
  Serial.begin(115200);
  pinMode(RS485_DE, OUTPUT);
  digitalWrite(RS485_DE, LOW);
  rs485.begin(BAUD_RATE, SERIAL_8N1, RS485_RX, RS485_TX);
  Serial.println("Modbus RTU Master ready");
}

void loop() {
  int16_t value = readHoldingRegister(SLAVE_ID, 0x0001);
  if (value >= 0) {
    Serial.println("Register 0x0001 = " + String(value));
  }
  delay(2000);
}

