  display.setTextSize(1);
  for (int i = 0; i < VISIBLE_ITEMS && (topItem + i) < menuCount; i++) {
    int idx = topItem + i;
    if (idx == currentItem) {
      display.fillRect(0, i * 16, 128, 16, SSD1306_WHITE);
      display.setTextColor(SSD1306_BLACK);
    } else {
      display.setTextColor(SSD1306_WHITE);
