  xTaskCreate(myTask, "Task", 1024, NULL, 1, NULL);
}
void loop() {}

output:
The task crashes immediately due to **stack overflow**. The `bigBuffer[4096]` array is allocated on the task's stack, but the task was created with only 1024 bytes of stack space — far too small.

**How it fails:** As soon as `myTask` executes and tries to allocate `char bigBuffer[4096]` on its stack, it overflows the 1024-byte stack, corrupting adjacent memory and causing a crash.

**Symptoms:** Immediate crash, Guru Meditation Error, or TaskWatchdog trigger right after task creation.

**Fix 1 – Increase stack size:**
```cpp
void myTask(void *param) {
  while(1) {
    char bigBuffer[4096];
    snprintf(bigBuffer, sizeof(bigBuffer), "Hello %d", random(1000));
    Serial.println(bigBuffer);
    vTaskDelay(pdMS_TO_TICKS(1000)); // use vTaskDelay, not delay()
  }
}
void setup() {
  Serial.begin(115200);
  // Stack size = 6144 bytes (>= local vars + function call overhead)
  xTaskCreate(myTask, "Task", 6144, NULL, 1, NULL);
}
void loop() {}
```

**Fix 2 – Move large buffer to heap or global scope:**
```cpp
char bigBuffer[4096]; // global: uses .bss RAM, not stack
void myTask(void *param) {
  while(1) {
    snprintf(bigBuffer, sizeof(bigBuffer), "Hello %d", random(1000));
    Serial.println(bigBuffer);
    vTaskDelay(pdMS_TO_TICKS(1000));
  }
}
void setup() {
  Serial.begin(115200);
  xTaskCreate(myTask, "Task", 2048, NULL, 1, NULL); // now 2048 is enough
}
```

**Debug stack usage:**
