  for (int i = 0; i < 16; i++) {
    sum += analogRead(VBAT_PIN);
    delayMicroseconds(100);
  }
  float adcVal = sum / 16.0;
  float voltage = (adcVal / ADC_RESOLUTION) * VREF * DIVIDER_RATIO;

  // ADC non-linearity correction (approximate)
  if (voltage < 1.0) voltage = 0;
  return voltage;
