  if (v >= 4.2) return 100;
  if (v <= 3.0) return 0;
  if (v >= 3.7) return (int)(50 + (v - 3.7) / (4.2 - 3.7) * 50);
  return (int)((v - 3.0) / (3.7 - 3.0) * 50);
}

