WebServer server(80);
void handleRequest() {
  String response = "";
  for(int i = 0; i < 10000; i++) {
    response += String(i) + "\n";
  }
  server.send(200, "text/plain", response);
}
void setup() {
  WiFi.begin("ssid", "pass");
  while(WiFi.status() != WL_CONNECTED) delay(500);
  server.on("/", handleRequest);
  server.begin();
}
