int movingAverage(int newSample) {
  static int buffer[10] = {0};
  static int sum = 0;
  static int index = 0;
  static bool filled = false;

  sum -= buffer[index];
  buffer[index] = newSample;
  sum += newSample;
  index = (index + 1) % 10;
  if(index == 0) filled = true;

  return filled ? sum / 10 : sum / (index == 0 ? 10 : index);
}

