#include <ArduinoJson.h>

#define COV_RATIO       0.2
#define NO_DUST_VOLTAGE 400
#define SYS_VOLTAGE     3300
const int iled = 12, vout = 36;
const char* ssid = "TestNet";
const char* password = "pass1234";
const char* fbUrl = "https://myproject.firebaseio.com/dust.json";

float readDustDensity() {
  digitalWrite(iled, HIGH);
  delayMicroseconds(280);
  int adc = analogRead(vout);
  delayMicroseconds(40);
  digitalWrite(iled, LOW);
  delayMicroseconds(9680);
  float voltage = (SYS_VOLTAGE / 4096.0) * adc * 11;
  return (voltage >= NO_DUST_VOLTAGE) ? (voltage - NO_DUST_VOLTAGE) * COV_RATIO : 0;
}

