#define BUFFER_SIZE 60
float readings[BUFFER_SIZE];
int bufIdx = 0;
bool bufFull = false;

void addReading(float density) {
  readings[bufIdx] = density;
  bufIdx = (bufIdx + 1) % BUFFER_SIZE;
  if(bufIdx == 0) bufFull = true;
}

float hourlyAverage() {
  int count = bufFull ? BUFFER_SIZE : bufIdx;
  if(count == 0) return 0;
  float sum = 0;
  for(int i = 0; i < count; i++) sum += readings[i];
  return sum / count;
}

void setup() {
  Serial.begin(115200);
  memset(readings, 0, sizeof(readings));
}

